// Lazy-loaded heavy dependencies (reduce cold start by ~1-2s)
// These are only require()'d and initialized when first accessed, not on every cold start.
// Uses Proxy so existing code (openai.chat..., bucket.file..., upload.single...) works unchanged.
function lazyInit(factory) {
  let instance;
  return new Proxy({}, {
    get(_, prop) {
      if (!instance) instance = factory();
      return typeof instance[prop] === 'function' ? instance[prop].bind(instance) : instance[prop];
    }
  });
}

const openai = lazyInit(() => {
  const OpenAI = require('openai');
  return new OpenAI({ apiKey: process.env.OPENAI_API_KEY });
});

const QRCode = lazyInit(() => require('qrcode'));

let _razorpayInstance;
function getRazorpay() {
  if (_razorpayInstance !== undefined) return _razorpayInstance;
  try {
    const Razorpay = require('razorpay');
    if (process.env.RAZORPAY_KEY_ID && process.env.RAZORPAY_KEY_SECRET) {
      _razorpayInstance = new Razorpay({ key_id: process.env.RAZORPAY_KEY_ID, key_secret: process.env.RAZORPAY_KEY_SECRET });
    } else { _razorpayInstance = null; }
  } catch (e) { _razorpayInstance = null; }
  return _razorpayInstance;
}

const upload = lazyInit(() => {
  const multer = require('multer');
  return multer({
    storage: multer.memoryStorage(),
    limits: { fileSize: 300 * 1024 * 1024, files: 10 },
    fileFilter: (req, file, cb) => {
      // Block dangerous executable/script file types, allow everything else
      const blockedTypes = [
        'application/x-msdownload',        // .exe, .dll
        'application/x-executable',         // Linux executables
        'application/x-msdos-program',      // .com, .bat
        'application/x-sh', 'application/x-bash', 'application/x-csh', // Shell scripts
        'application/x-httpd-php',          // PHP
        'application/javascript', 'text/javascript', // JS
        'application/x-python-code',        // Python
        'application/java-archive',         // .jar
        'application/x-ms-shortcut',        // .lnk
        'application/x-msi',               // .msi
        'application/vnd.microsoft.portable-executable', // PE files
      ];
      const blockedExtensions = [
        '.exe', '.dll', '.bat', '.cmd', '.com', '.msi', '.scr', '.pif',
        '.vbs', '.vbe', '.js', '.jse', '.wsf', '.wsh', '.ps1', '.psm1',
        '.sh', '.bash', '.csh', '.ksh', '.php', '.py', '.rb', '.pl',
        '.jar', '.class', '.lnk', '.inf', '.reg', '.hta', '.cpl',
      ];
      const ext = '.' + (file.originalname || '').split('.').pop().toLowerCase();
      if (blockedTypes.includes(file.mimetype) || blockedExtensions.includes(ext)) {
        cb(new Error('This file type is not allowed for security reasons.'), false);
      } else {
        cb(null, true);
      }
    }
  });
});

const bucket = lazyInit(() => {
  const { Storage } = require('@google-cloud/storage');
  let storage;
  try {
    const credentialsJson = process.env.GOOGLE_APPLICATION_CREDENTIALS_JSON;
    if (credentialsJson && credentialsJson !== 'undefined') {
      const serviceAccount = JSON.parse(credentialsJson);
      storage = new Storage({
        projectId: serviceAccount.project_id,
        credentials: { client_email: serviceAccount.client_email, private_key: serviceAccount.private_key }
      });
    } else {
      // Fall back to ADC (works in production via GOOGLE_APPLICATION_CREDENTIALS file)
      storage = new Storage();
    }
  } catch (e) {
    console.error('⚠️ Failed to init Storage with JSON creds, falling back to ADC:', e.message);
    storage = new Storage();
  }
  return storage.bucket(process.env.FIREBASE_STORAGE_BUCKET || 'dine-menu-uploads');
});

