// Pre-compute daily analytics stats on every order write (fire-and-forget)
// Doc ID: {restaurantId}_{YYYY-MM-DD} in 'dailyStats' collection
function updateDailyStats(restaurantId, order, operation) {
  try {
    const orderDate = order.createdAt?.toDate ? order.createdAt.toDate()
      : (order.createdAt instanceof Date ? order.createdAt : new Date(order.createdAt || Date.now()));
    const dateStr = orderDate.toISOString().split('T')[0];
    const docId = `${restaurantId}_${dateStr}`;
    const statsRef = db.collection('dailyStats').doc(docId);

    const sign = operation === 'add' ? 1 : -1;
    const amount = (order.totalAmount || 0) * sign;
    const amountWithTax = (order.finalAmount || order.totalAmount || 0) * sign;

    // Build atomic update
    const update = {
      restaurantId,
      date: dateStr,
      totalOrders: FieldValue.increment(sign),
      totalRevenue: FieldValue.increment(amount),
      totalRevenueWithTax: FieldValue.increment(amountWithTax),
      updatedAt: FieldValue.serverTimestamp()
    };

    // Order type bucket
    const orderType = (order.orderType || 'dine_in').toLowerCase().replace(/[\s-]+/g, '_');
    update[`ordersByType_${orderType}`] = FieldValue.increment(sign);

    // Busy hour bucket
    const hour = orderDate.getHours();
    update[`hour_${hour.toString().padStart(2, '0')}`] = FieldValue.increment(sign);

    // Customer tracking (only add, never remove from array)
    const customerId = order.customerId || order.customerInfo?.phone || null;
    if (customerId && operation === 'add') {
      update.customerIds = FieldValue.arrayUnion(customerId);
    }

    // Item counts — use set+merge with increment for qty/revenue per item
    if (order.items && Array.isArray(order.items)) {
      const itemCounts = {};
      order.items.forEach(item => {
        const name = item.name || item.itemName;
        if (name) {
          const key = name.replace(/[.\/]/g, '_'); // Firestore key-safe
          if (!itemCounts[key]) itemCounts[key] = { qty: 0, revenue: 0 };
          itemCounts[key].qty += (item.quantity || 1) * sign;
          itemCounts[key].revenue += ((item.price || 0) * (item.quantity || 1)) * sign;
        }
      });
      // Flatten into dot-notation fields for atomic merge
      for (const [key, val] of Object.entries(itemCounts)) {
        update[`itemCounts.${key}.qty`] = FieldValue.increment(val.qty);
        update[`itemCounts.${key}.revenue`] = FieldValue.increment(val.revenue);
      }
    }

    statsRef.set(update, { merge: true })
      .catch(err => console.error('dailyStats update error (non-blocking):', err));
  } catch (err) {
    console.error('dailyStats helper error (non-blocking):', err);
  }
}

// Update dailyStats when order amount changes (PATCH with items update)
function updateDailyStatsRevenueDiff(restaurantId, order, oldAmount, newAmount, oldFinalAmount, newFinalAmount) {
  try {
    const orderDate = order.createdAt?.toDate ? order.createdAt.toDate()
      : (order.createdAt instanceof Date ? order.createdAt : new Date(order.createdAt || Date.now()));
    const dateStr = orderDate.toISOString().split('T')[0];
    const docId = `${restaurantId}_${dateStr}`;
    const statsRef = db.collection('dailyStats').doc(docId);

    const diff = (newAmount || 0) - (oldAmount || 0);
    const diffWithTax = (newFinalAmount || newAmount || 0) - (oldFinalAmount || oldAmount || 0);

    if (diff === 0 && diffWithTax === 0) return;

    const update = {
      restaurantId,
      date: dateStr,
      updatedAt: FieldValue.serverTimestamp()
    };
    if (diff !== 0) update.totalRevenue = FieldValue.increment(diff);
    if (diffWithTax !== 0) update.totalRevenueWithTax = FieldValue.increment(diffWithTax);

    statsRef.set(update, { merge: true })
      .catch(err => console.error('dailyStats revenue diff error (non-blocking):', err));
  } catch (err) {
    console.error('dailyStats revenueDiff helper error (non-blocking):', err);
  }
}

// Calculate pricing adjustments (zone surcharge, time-based pricing)
function calculatePricingAdjustments(restaurantData, { tableSection, floorData, orderTime, subtotal }) {
  const result = { zoneSurcharge: 0, appliedRules: [] };

  // Priority 1: Floor-level area charge (simple, set directly on the floor)
  if (floorData?.areaChargeType && floorData.areaChargeType !== 'none' && floorData.areaChargeValue > 0 && subtotal > 0) {
    const surcharge = floorData.areaChargeType === 'percentage'
      ? Math.round((subtotal * floorData.areaChargeValue / 100) * 100) / 100
      : Math.round(floorData.areaChargeValue * 100) / 100;
    result.zoneSurcharge = surcharge;
    result.appliedRules.push({
      type: 'floor_area_charge',
      floorName: floorData.name,
      markupType: floorData.areaChargeType,
      markupValue: floorData.areaChargeValue,
      surchargeAmount: surcharge
    });
    return result; // Floor charge takes priority, skip zone pricing
  }

  // Priority 2: Zone pricing settings (advanced, sectionMatch-based)
  const pricingSettings = restaurantData.pricingSettings;
  if (!pricingSettings) return result;

  const zonePricing = pricingSettings.zonePricing;
  if (zonePricing?.enabled && tableSection && Array.isArray(zonePricing.zones)) {
    const matchedZone = zonePricing.zones.find(z =>
      z.isActive && z.sectionMatch && tableSection.toLowerCase().includes(z.sectionMatch.toLowerCase())
    );
    if (matchedZone && subtotal > 0) {
      const surcharge = matchedZone.markupType === 'percentage'
        ? Math.round((subtotal * (matchedZone.markupValue || 0) / 100) * 100) / 100
        : Math.round((matchedZone.markupValue || 0) * 100) / 100;
      result.zoneSurcharge = surcharge;
      result.appliedRules.push({
        type: 'zone',
        zoneId: matchedZone.id,
        zoneName: matchedZone.name,
        markupType: matchedZone.markupType,
        markupValue: matchedZone.markupValue,
        surchargeAmount: surcharge
      });
    }
  }

  return result;
}

// Channel name constants for pricing rule identification
const DINEIN_NAMES = ['dine-in', 'dine in', 'dinein'];
const TAKEAWAY_NAMES = ['takeaway', 'take away', 'take-away'];
const DELIVERY_NAMES = ['delivery'];
const CHANNEL_NAMES = [...DINEIN_NAMES, ...TAKEAWAY_NAMES, ...DELIVERY_NAMES];

function isZoneRule(rule) {
  return !CHANNEL_NAMES.includes((rule?.name || '').toLowerCase().trim());
}
function findDineInRule(rules) {
  return (rules || []).find(r => r.isActive && DINEIN_NAMES.includes((r.name || '').toLowerCase().trim()));
}

// --- Per-Item Tax Resolution ---
// Resolves which taxes apply to a given order item based on:
//   Priority 1: item.taxGroupId (item-level override)
//   Priority 2: category.taxGroupId (category-level)
//   Priority 3: restaurant default taxes (taxSettings.taxes)
//   When a tax group has alsoApplyGlobalTax: true, both group taxes AND global taxes apply.
//   By default (alsoApplyGlobalTax: false/undefined), group taxes override global taxes.
function resolveTaxesForItem(item, taxSettings, categories) {
  if (!taxSettings?.enabled) return [];
  const groups = taxSettings.taxGroups || [];
  const globalTaxes = (taxSettings.taxes && taxSettings.taxes.length > 0)
    ? taxSettings.taxes.filter(t => t.enabled)
    : (taxSettings.defaultTaxRate
      ? [{ name: 'Tax', rate: taxSettings.defaultTaxRate, type: 'percentage' }]
      : []);

  // Resolve a tax group, optionally merging global taxes if alsoApplyGlobalTax is true
  const resolveGroup = (group) => {
    const groupTaxes = group.taxes || [];
    if (group.alsoApplyGlobalTax && globalTaxes.length > 0) {
      const merged = [...groupTaxes];
      for (const gt of globalTaxes) {
        if (!merged.some(t => t.name === gt.name && t.rate === gt.rate)) merged.push(gt);
      }
      return merged;
    }
    return groupTaxes;
  };

  // Priority 1: Item-level tax group
  if (item.taxGroupId) {
    const group = groups.find(g => g.id === item.taxGroupId);
    if (group) return resolveGroup(group);
  }

  // Priority 2: Category-level tax group
  const catId = item.category || item.categoryId;
  if (catId && categories && categories.length > 0) {
    const cat = categories.find(c => c.id === catId || c.name === catId);
    if (cat?.taxGroupId) {
      const group = groups.find(g => g.id === cat.taxGroupId);
      if (group) return resolveGroup(group);
    }
  }

  // Priority 3: Restaurant default taxes (global)
  return globalTaxes;
}

// Calculate per-item tax and aggregate by (name, rate)
// Supports discountApplicable: when false, item gets 0 discount share (full tax on price)
function calculatePerItemTax(orderItems, taxSettings, categories, totalDiscount, serviceChargeAmount) {
  const subtotal = orderItems.reduce((sum, item) => sum + (item.total || item.price * item.quantity), 0);

  // Discountable subtotal: only items where discountApplicable !== false
  const discountableSubtotal = orderItems.reduce((sum, item) => {
    if (item.discountApplicable === false) return sum;
    return sum + (item.total || item.price * item.quantity);
  }, 0);

  const taxTotals = {}; // key: "name|rate" => { name, rate, amount }
  let totalTaxAmount = 0;

  for (const item of orderItems) {
    const itemTotal = item.total || item.price * item.quantity;
    const isDiscountable = item.discountApplicable !== false;

    // Proportional discount share: only among discountable items
    const itemDiscShare = (isDiscountable && discountableSubtotal > 0)
      ? (itemTotal / discountableSubtotal) * totalDiscount
      : 0;
    const itemTaxable = Math.max(0, itemTotal - itemDiscShare);
    // Service charge distributed across ALL items (applies universally)
    const itemSCShare = subtotal > 0 ? (itemTotal / subtotal) * (serviceChargeAmount || 0) : 0;
    const itemTaxableWithSC = itemTaxable + itemSCShare;

    const itemTaxes = resolveTaxesForItem(item, taxSettings, categories);
    let itemTaxAmount = 0;

    for (const tax of itemTaxes) {
      const amt = Math.round((itemTaxableWithSC * (tax.rate || 0) / 100) * 100) / 100;
      const key = `${tax.name || 'Tax'}|${tax.rate || 0}`;
      if (!taxTotals[key]) taxTotals[key] = { name: tax.name || 'Tax', rate: tax.rate || 0, amount: 0 };
      taxTotals[key].amount += amt;
      itemTaxAmount += amt;
      totalTaxAmount += amt;
    }

    // Store per-item tax amount for audit trail
    item.itemTaxAmount = Math.round(itemTaxAmount * 100) / 100;
    item.taxGroupId = item.taxGroupId || null;
  }

  const taxBreakdown = Object.values(taxTotals).map(t => ({
    ...t,
    amount: Math.round(t.amount * 100) / 100
  }));

  return { taxBreakdown, totalTaxAmount: Math.round(totalTaxAmount * 100) / 100 };
}

// --- Menu Item ↔ Inventory Linkage Helpers ---

function getInventoryUnitForMenuItem(menuItem) {
  if (menuItem.bottleSize) return 'bottle';
  if (menuItem.servingUnit) return menuItem.servingUnit;
  if (menuItem.unit) return menuItem.unit;
  if (menuItem.servingSize) return menuItem.servingSize === 'scoop' ? 'scoop' : 'pcs';
  return 'pcs';
}

async function linkMenuItemToInventory(restaurantId, menuItem, userId) {
  try {
    const unit = getInventoryUnitForMenuItem(menuItem);
    const stockQty = parseFloat(menuItem.stockQuantity) || 0;
    const minStock = parseFloat(menuItem.lowStockThreshold) || 5;

    // Check if linked inventory item already exists
    let inventoryItemId = null;
    const existingSnap = await db.collection(collections.inventory)
      .where('restaurantId', '==', restaurantId)
      .where('linkedMenuItemId', '==', menuItem.id)
      .limit(1)
      .get();

    if (!existingSnap.empty) {
      // Update existing linked inventory item
      inventoryItemId = existingSnap.docs[0].id;
      const currentItem = existingSnap.docs[0].data();
      const updateData = {
        name: menuItem.name,
        currentStock: stockQty,
        minStock,
        unit,
        updatedAt: new Date(),
        updatedBy: userId
      };
      if (menuItem.expiryDate) updateData.expiryDate = menuItem.expiryDate;
      if (menuItem.mfgDate) updateData.mfgDate = menuItem.mfgDate;
      if (menuItem.shelfLife) updateData.expiryDays = menuItem.shelfLife;
      // Recalculate status
      updateData.status = stockQty <= minStock ? 'low' : 'good';
      if (menuItem.expiryDate && new Date(menuItem.expiryDate) < new Date()) updateData.status = 'expired';

      await db.collection(collections.inventory).doc(inventoryItemId).update(updateData);

      // If stock changed, create/update batch
      const oldStock = parseFloat(currentItem.currentStock) || 0;
      const stockDiff = stockQty - oldStock;
      if (stockDiff > 0) {
        await db.collection(collections.stockBatches).add({
          restaurantId, inventoryItemId, inventoryItemName: menuItem.name,
          quantity: stockDiff, remainingQty: stockDiff, unit,
          mfgDate: menuItem.mfgDate ? new Date(menuItem.mfgDate) : new Date(),
          expiryDays: menuItem.shelfLife ? parseInt(menuItem.shelfLife) : null,
          expiryDate: menuItem.expiryDate ? new Date(menuItem.expiryDate) : null,
          costPerUnit: menuItem.price ? menuItem.price * 0.3 : 0,
          supplier: '', addedBy: userId, source: 'menu-link',
          status: 'active', createdAt: new Date(), updatedAt: new Date()
        });
      }
      console.log(`📦 Menu→Inventory sync updated: ${menuItem.name} (${inventoryItemId}) stock=${stockQty}`);
    } else {
      // Create new inventory item
      let status = 'good';
      if (stockQty <= minStock) status = 'low';
      if (menuItem.expiryDate && new Date(menuItem.expiryDate) < new Date()) status = 'expired';

      const itemData = {
        restaurantId,
        name: menuItem.name,
        category: menuItem.category || 'other',
        unit,
        currentStock: stockQty,
        minStock,
        maxStock: 0,
        costPerUnit: menuItem.price ? Math.round(menuItem.price * 0.3 * 100) / 100 : 0,
        supplier: '',
        description: menuItem.description || '',
        barcode: '',
        expiryDate: menuItem.expiryDate || null,
        mfgDate: menuItem.mfgDate || null,
        expiryDays: menuItem.shelfLife ? parseInt(menuItem.shelfLife) : null,
        location: '',
        status,
        linkedMenuItemId: menuItem.id,
        createdAt: new Date(),
        updatedAt: new Date(),
        createdBy: userId,
        updatedBy: userId
      };

      const itemRef = await db.collection(collections.inventory).add(itemData);
      inventoryItemId = itemRef.id;

      // Create initial stock batch
      if (stockQty > 0) {
        await db.collection(collections.stockBatches).add({
          restaurantId, inventoryItemId, inventoryItemName: menuItem.name,
          quantity: stockQty, remainingQty: stockQty, unit,
          mfgDate: menuItem.mfgDate ? new Date(menuItem.mfgDate) : new Date(),
          expiryDays: menuItem.shelfLife ? parseInt(menuItem.shelfLife) : null,
          expiryDate: menuItem.expiryDate ? new Date(menuItem.expiryDate) : null,
          costPerUnit: itemData.costPerUnit, supplier: '',
          addedBy: userId, source: 'menu-link',
          status: 'active', createdAt: new Date(), updatedAt: new Date()
        });
      }
      console.log(`📦 Menu→Inventory created: ${menuItem.name} (${inventoryItemId}) stock=${stockQty}`);
    }

    // Ensure a 1:1 recipe exists for this menu item
    const recipeSnap = await db.collection(collections.recipes)
      .where('restaurantId', '==', restaurantId)
      .where('menuItemId', '==', menuItem.id)
      .limit(1)
      .get();

    if (recipeSnap.empty && inventoryItemId) {
      await db.collection(collections.recipes).add({
        restaurantId,
        menuItemId: menuItem.id,
        menuItemName: menuItem.name,
        name: `${menuItem.name} (Stock-Linked)`,
        description: 'Auto-generated 1:1 recipe for stock tracking',
        ingredients: [{
          inventoryItemId,
          inventoryItemName: menuItem.name,
          quantity: 1,
          unit
        }],
        isAutoGenerated: true,
        isActive: true,
        createdAt: new Date(),
        updatedAt: new Date(),
        createdBy: userId
      });
      console.log(`📋 1:1 recipe created for: ${menuItem.name}`);
    }

    return inventoryItemId;
  } catch (err) {
    console.error('linkMenuItemToInventory error:', err);
    return null;
  }
}

async function syncInventoryToMenuItem(restaurantId, inventoryItemId) {
  try {
    const itemDoc = await db.collection(collections.inventory).doc(inventoryItemId).get();
    if (!itemDoc.exists) return;
    const invItem = itemDoc.data();
    if (!invItem.linkedMenuItemId) return;

    const restaurantRef = db.collection(collections.restaurants).doc(restaurantId);
    const restaurantDoc = await restaurantRef.get();
    if (!restaurantDoc.exists) return;

    const restaurantData = restaurantDoc.data();
    const menuItems = restaurantData.menu?.items || [];
    let changed = false;

    const updatedItems = menuItems.map(mi => {
      if (mi.id !== invItem.linkedMenuItemId) return mi;
      const newQty = Math.max(0, Math.round(invItem.currentStock));
      const newAvail = newQty > 0;
      if (mi.stockQuantity === newQty && mi.isAvailable === newAvail) return mi;
      changed = true;
      return { ...mi, stockQuantity: newQty, isAvailable: newAvail, updatedAt: new Date() };
    });

    if (changed) {
      await restaurantRef.update({
        'menu.items': updatedItems,
        'menu.lastUpdated': new Date()
      });
      invalidateRestaurantCache(restaurantId);
      console.log(`🔄 Inventory→Menu sync: ${invItem.name} stock=${Math.round(invItem.currentStock)}`);
    }
  } catch (err) {
    console.error('syncInventoryToMenuItem error:', err);
  }
}

async function syncInventoryStockToMenuItems(restaurantId) {
  try {
    const invSnap = await db.collection(collections.inventory)
      .where('restaurantId', '==', restaurantId)
      .where('linkedMenuItemId', '!=', null)
      .get();

    if (invSnap.empty) return;

    const restaurantRef = db.collection(collections.restaurants).doc(restaurantId);
    const restaurantDoc = await restaurantRef.get();
    if (!restaurantDoc.exists) return;

    const restaurantData = restaurantDoc.data();
    const menuItems = restaurantData.menu?.items || [];
    let changed = false;

    const invMap = {};
    invSnap.docs.forEach(doc => {
      const d = doc.data();
      if (d.linkedMenuItemId) invMap[d.linkedMenuItemId] = d;
    });

    const updatedItems = menuItems.map(mi => {
      const inv = invMap[mi.id];
      if (!inv) return mi;
      const newQty = Math.max(0, Math.round(inv.currentStock));
      const newAvail = newQty > 0;
      if (mi.stockQuantity === newQty && mi.isAvailable === newAvail) return mi;
      changed = true;
      return { ...mi, stockQuantity: newQty, isAvailable: newAvail, updatedAt: new Date() };
    });

    if (changed) {
      await restaurantRef.update({
        'menu.items': updatedItems,
        'menu.lastUpdated': new Date()
      });
      invalidateRestaurantCache(restaurantId);
      console.log(`🔄 Bulk inventory→menu sync for ${restaurantId}`);
    }
  } catch (err) {
    console.error('syncInventoryStockToMenuItems error:', err);
  }
}

// Multi-tier pricing: resolve per-item price for a given pricing rule
function resolveItemPriceForRule(menuItem, ruleId, rules) {
  if (!ruleId || !rules?.length) return null;
  const rule = rules.find(r => r.id === ruleId && r.isActive);
  if (!rule) return null;
  // Priority 1: Per-item specific price
  if (menuItem.pricingRules && typeof menuItem.pricingRules[ruleId] === 'number') {
    return menuItem.pricingRules[ruleId];
  }
  // Priority 2 (zone rules only): Inherit from Dine-In per-item price
  if (isZoneRule(rule)) {
    const dineInRule = findDineInRule(rules);
    if (dineInRule && menuItem.pricingRules && typeof menuItem.pricingRules[dineInRule.id] === 'number') {
      return menuItem.pricingRules[dineInRule.id];
    }
  }
  // Priority 3: Rule's default markup
  const basePrice = menuItem.price;
  if (rule.defaultMarkupType === 'percentage' && rule.defaultMarkupValue) {
    return Math.round(basePrice * (1 + rule.defaultMarkupValue / 100) * 100) / 100;
  }
  if (rule.defaultMarkupType === 'flat' && rule.defaultMarkupValue) {
    return Math.round((basePrice + rule.defaultMarkupValue) * 100) / 100;
  }
  return null; // no adjustment — use base price
}

// Multi-tier pricing: resolve which pricing rule applies based on floor name
function resolveTablePricingRule(floorName, multiPricing) {
  if (!multiPricing?.enabled || !floorName) return null;
  for (const rule of (multiPricing.rules || [])) {
    if (!rule.isActive) continue;
    for (const mapping of (rule.tableMappings || [])) {
      if (mapping && floorName.toLowerCase().includes(mapping.toLowerCase())) {
        return rule.id;
      }
    }
  }
  return null;
}

// Generate daily order ID (starts from 1 each day)
async function generateDailyOrderId(restaurantId) {
  try {
    const today = new Date();
    const todayStr = today.toISOString().split('T')[0]; // YYYY-MM-DD format
    
    // Get or create daily counter document
    const counterRef = db.collection('daily_order_counters').doc(`${restaurantId}_${todayStr}`);
    const counterDoc = await counterRef.get();
    
    if (!counterDoc.exists) {
      // First order of the day - start from 1
      await counterRef.set({
        restaurantId,
        date: todayStr,
        lastOrderId: 1,
        createdAt: new Date(),
        updatedAt: new Date()
      });
      return 1;
    } else {
      // Increment the counter
      const counterData = counterDoc.data();
      const newOrderId = counterData.lastOrderId + 1;
      
      await counterRef.update({
        lastOrderId: newOrderId,
        updatedAt: new Date()
      });
      
      return newOrderId;
    }
  } catch (error) {
    console.error('Error generating daily order ID:', error);
    // Fallback to timestamp-based ID
    return Date.now() % 10000; // Last 4 digits of timestamp
  }
}

// Generate sequential order ID (never resets; increments forever per restaurant). Uses transaction to avoid race conditions.
async function generateSequentialOrderId(restaurantId) {
  try {
    const counterRef = db.collection('order_id_counters').doc(restaurantId);
    const result = await db.runTransaction(async (transaction) => {
      const snap = await transaction.get(counterRef);
      const nextId = snap.exists ? ((snap.data().lastOrderId || 0) + 1) : 1;
      transaction.set(counterRef, {
        restaurantId,
        lastOrderId: nextId,
        updatedAt: new Date()
      }, { merge: true });
      return nextId;
    });
    return result;
  } catch (error) {
    console.error('Error generating sequential order ID:', error);
    return Date.now() % 100000;
  }
}

// Resolves next display order ID: daily (reset each day) or sequential (never reset) based on restaurant.orderSettings.sequentialOrderIdEnabled
async function getNextOrderId(restaurantId, restaurantDataOrNull) {
  let restaurantData = restaurantDataOrNull;
  if (!restaurantData) {
    const restaurantDoc = await db.collection(collections.restaurants).doc(restaurantId).get();
    restaurantData = restaurantDoc.exists ? restaurantDoc.data() : {};
  }
  const useSequential = !!(restaurantData.orderSettings && restaurantData.orderSettings.sequentialOrderIdEnabled);
  if (useSequential) {
    return await generateSequentialOrderId(restaurantId);
  }
  return await generateDailyOrderId(restaurantId);
}

// Generate next tab number for bar tabs (daily reset, atomic via transaction)
async function getNextTabNumber(restaurantId) {
  try {
    const today = new Date().toISOString().split('T')[0]; // YYYY-MM-DD
    const counterRef = db.collection('tab_counters').doc(restaurantId);
    const result = await db.runTransaction(async (transaction) => {
      const snap = await transaction.get(counterRef);
      let nextNum = 1;
      if (snap.exists) {
        const data = snap.data();
        // Reset if new day, otherwise increment
        nextNum = (data.date === today) ? (data.lastTabNumber + 1) : 1;
      }
      transaction.set(counterRef, {
        restaurantId,
        date: today,
        lastTabNumber: nextNum,
        updatedAt: new Date()
      });
      return nextNum;
    });
    return result;
  } catch (error) {
    console.error('Error generating tab number:', error);
    return Date.now() % 1000; // fallback
  }
}

// Helper: build plain-text invoice for WhatsApp bill sending
function buildInvoiceText(order, restaurant) {
  const lines = [];
  lines.push('================================');
  lines.push(`  ${restaurant.name || 'Restaurant'}`);
  if (restaurant.legalName) lines.push(`  ${restaurant.legalName}`);
  if (restaurant.showGstOnInvoice && restaurant.gstin) lines.push(`GSTIN: ${restaurant.gstin}`);
  if (restaurant.address) lines.push(restaurant.address);
  lines.push('================================');
  lines.push(`Order #${order.dailyOrderId || order.orderNumber || (order.id || '').slice(-6)}`);
  lines.push(`Date: ${new Date().toLocaleString('en-IN')}`);
  if (order.tableNumber) lines.push(`Table: ${order.tableNumber}`);
  lines.push('--------------------------------');
  (order.items || []).forEach(item => {
    const total = (item.price * item.quantity).toFixed(2);
    lines.push(`${item.name} x${item.quantity}  ₹${total}`);
  });
  lines.push('--------------------------------');
  const subtotal = order.totalAmount || order.subtotal || 0;
  lines.push(`Subtotal: ₹${Number(subtotal).toFixed(2)}`);
  if (order.discountAmount > 0) lines.push(`Discount: -₹${Number(order.discountAmount).toFixed(2)}`);
  if (order.taxAmount > 0) lines.push(`Tax: ₹${Number(order.taxAmount).toFixed(2)}`);
  if (order.serviceChargeAmount > 0) lines.push(`Service Charge: ₹${Number(order.serviceChargeAmount).toFixed(2)}`);
  if (order.tipAmount > 0) lines.push(`Tip: ₹${Number(order.tipAmount).toFixed(2)}`);
  if (order.roundOffAmount) lines.push(`Round Off: ₹${Number(order.roundOffAmount).toFixed(2)}`);
  lines.push('================================');
  lines.push(`TOTAL: ₹${Number(order.finalAmount || order.totalAmount || 0).toFixed(2)}`);
  lines.push(`Payment: ${(order.paymentMethod || 'cash').toUpperCase()}`);
  lines.push('================================');
  lines.push('Thank you for your visit!');
  return lines.join('\n');
}

// Helper function to create default free-trial subscription for new users
async function createDefaultSubscription(userId, email, phone, role) {
  try {
    // Check if subscription already exists
    const userRef = db.collection('dine_user_data').doc(userId);
    const userDoc = await userRef.get();

    if (userDoc.exists) {
      console.log(`[SUBSCRIPTION] User ${userId} already has subscription record`);
      return;
    }

    // Create subscription with free-trial plan
    const currentDate = new Date();
    const planDetails = {
      name: 'Free Trial',
      features: {
        maxProducts: 200,
        maxLocations: 1,
        maxTransactions: 'unlimited',
        inventoryTracking: true,
        multiStore: false,
        advancedReports: false,
        prioritySupport: false,
        backupEnabled: false,
        staffAccounts: 1,
        tableManagement: 100
      }
    };

    const newUserData = {
      uid: userId,
      email: email || '',
      phone: phone || '',
      role: role || 'owner',
      restaurantInfo: {},
      createdAt: currentDate.toISOString(),
      lastUpdated: currentDate.toISOString(),
      app: 'Dine',
      subscription: {
        planId: 'free-trial',
        planName: planDetails.name,
        status: 'active',
        startDate: currentDate.toISOString(),
        endDate: null, // Free trial has no end date
        features: planDetails.features,
        lastUpdated: currentDate.toISOString(),
        app: 'Dine'
      }
    };

    await userRef.set(newUserData);
    console.log(`✅ Created free-trial subscription for user ${userId}`);
  } catch (error) {
    console.error(`❌ Error creating default subscription for user ${userId}:`, error);
    // Don't throw - allow user registration to continue even if subscription creation fails
  }
}

