// Enhanced function to extract menu from any file type (images, PDFs, docs, CSV, etc.)
// All extractors return { categories: [{ name, order }], menuItems: [...] }
const extractMenuFromAnyFile = async (fileUrl, fileType, fileName, businessType = 'restaurant') => {
  try {
    console.log(`🔍 Starting enhanced menu extraction for ${fileType} file: ${fileName} (businessType: ${businessType})`);
    let result;
    if (fileType.startsWith('image/')) {
      result = await extractMenuFromImage(fileUrl, businessType);
    } else if (fileType === 'application/pdf') {
      result = await extractMenuFromPDF(fileUrl, businessType);
    } else if (fileType.includes('csv') || fileType.includes('excel') || fileType.includes('spreadsheet')) {
      result = await extractMenuFromCSV(fileUrl, businessType);
    } else if (fileType.includes('document') || fileType.includes('text')) {
      result = await extractMenuFromDocument(fileUrl, businessType);
    } else {
      console.log('⚠️ Unknown file type, attempting image extraction as fallback...');
      result = await extractMenuFromImage(fileUrl, businessType);
    }
    if (!Array.isArray(result.categories)) result.categories = [];
    if (!Array.isArray(result.menuItems)) result.menuItems = [];
    return result;
  } catch (error) {
    console.error('❌ Enhanced extraction failed:', error);
    return { categories: [], menuItems: [] };
  }
};

// Extract menu from PDF files. Returns { categories, menuItems }. Prefer section headers from document as categories.
const MENU_PDF_PROMPT = `Analyze this document. If it is a restaurant menu: 1) List section headers in "categories" as [{"name":"SectionName","order":1}]. Use EXACT names. If no sections, use "categories":[].
2) Extract ALL menu items. Set "category" to section name or "Other".
3) VARIANTS: If item shows multiple sizes/prices (e.g., "Half ₹110/Full ₹180", "110/180"), extract as "variants":[{"name":"Half","price":110},{"name":"Full","price":180}]. Otherwise use "variants":[].
For each item also add "imageKeyword": a specific hyphen-separated keyword (1-3 words) that uniquely identifies this dish. Make each keyword DIFFERENT from similar items: "egg-thali" not "thali", "chicken-biryani" not "biryani", "masala-dosa" not "dosa", "chocolate-icecream" not "icecream", "chicken-burger" not "burger". Use the protein/variant as prefix (e.g. "mutton-thali", "veg-fried-rice", "strawberry-shake", "cheese-naan").
Return JSON: {"categories":[...],"menuItems":[{"name":"","description":"","price":0,"category":"...","isVeg":true,"shortCode":"1","variants":[],"imageKeyword":""}]}
shortCode: 1,2,3... If NOT a menu: {"categories":[],"menuItems":[]}`;

// Primary path: upload PDF to OpenAI Files API and reference via file_id.
// gpt-4o reads both text + visual layout/images of each page natively.
const extractMenuFromPDFViaFilesAPI = async (buffer, fileName) => {
  console.log('📤 Uploading PDF to OpenAI Files API...');
  const { toFile } = require('openai');
  const uploaded = await openai.files.create({
    file: await toFile(buffer, fileName || 'menu.pdf', { type: 'application/pdf' }),
    purpose: 'user_data'
  });
  console.log(`✅ Uploaded as ${uploaded.id}`);

  try {
    const response = await openai.chat.completions.create({
      model: "gpt-4o",
      messages: [
        {
          role: "user",
          content: [
            { type: "file", file: { file_id: uploaded.id } },
            { type: "text", text: MENU_PDF_PROMPT }
          ]
        }
      ],
      max_tokens: 8000,
      temperature: 0.1,
      response_format: { type: "json_object" }
    });
    const content = response.choices[0].message.content;
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const d = JSON.parse(jsonMatch[0]);
      return { categories: Array.isArray(d.categories) ? d.categories : [], menuItems: Array.isArray(d.menuItems) ? d.menuItems : [] };
    }
    return { categories: [], menuItems: [] };
  } finally {
    // Clean up uploaded file
    openai.files.del(uploaded.id).catch(err => console.warn('Failed to delete OpenAI file:', err.message));
  }
};

const extractMenuFromPDF = async (pdfUrl, businessType = 'restaurant') => {
  console.log('📄 Extracting menu from PDF...');
  console.log('📥 Downloading PDF...');
  const buffer = await downloadFileBuffer(pdfUrl);
  const fileName = pdfUrl.split('/').pop().split('?')[0] || 'menu.pdf';

  // Try 1: OpenAI native PDF (Files API + gpt-4o) — best, reads visual layout + text
  try {
    const result = await extractMenuFromPDFViaFilesAPI(buffer, fileName);
    if (result.menuItems.length > 0) {
      console.log(`✅ Files API path extracted ${result.menuItems.length} items`);
      return result;
    }
    console.log('⚠️ Files API returned 0 items, trying text fallback...');
  } catch (err) {
    console.warn('⚠️ Files API path failed, falling back to pdf-parse:', err.message);
  }

  // Try 2: Fallback — pdf-parse text extraction + GPT-4o
  try {
    const pdfParse = require('pdf-parse');
    const parsed = await pdfParse(buffer);
    const textContent = (parsed.text || '').trim();
    console.log(`📄 Parsed PDF to text (${textContent.length} chars, ${parsed.numpages} pages)`);

    if (!textContent) {
      console.log('⚠️ PDF has no extractable text (scanned/image-only PDF).');
      return { categories: [], menuItems: [] };
    }

    const response = await openai.chat.completions.create({
      model: "gpt-4o",
      messages: [
        {
          role: "user",
          content: `${MENU_PDF_PROMPT}\n\nPDF TEXT:\n"""\n${textContent.slice(0, 60000)}\n"""`
        }
      ],
      max_tokens: 8000,
      temperature: 0.1,
      response_format: { type: "json_object" }
    });
    const content = response.choices[0].message.content;
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const d = JSON.parse(jsonMatch[0]);
      return { categories: Array.isArray(d.categories) ? d.categories : [], menuItems: Array.isArray(d.menuItems) ? d.menuItems : [] };
    }
    return { categories: [], menuItems: [] };
  } catch (error) {
    console.error('❌ PDF extraction failed:', error);
    return { categories: [], menuItems: [] };
  }
};

// Helper: download file from URL and return buffer
const downloadFileBuffer = async (url) => {
  const axios = require('axios');
  const response = await axios.get(url, { responseType: 'arraybuffer' });
  return Buffer.from(response.data);
};

// Helper: parse Excel/CSV file buffer to text table
const parseSpreadsheetToText = (buffer, fileName) => {
  const XLSX = require('xlsx');
  const workbook = XLSX.read(buffer, { type: 'buffer' });
  const lines = [];
  for (const sheetName of workbook.SheetNames) {
    const sheet = workbook.Sheets[sheetName];
    const data = XLSX.utils.sheet_to_csv(sheet);
    if (data.trim()) {
      if (workbook.SheetNames.length > 1) lines.push(`--- Sheet: ${sheetName} ---`);
      lines.push(data);
    }
  }
  return lines.join('\n');
};

// Helper: parse Word document buffer to text
const parseDocumentToText = async (buffer, fileName) => {
  const ext = (fileName || '').split('.').pop().toLowerCase();
  if (ext === 'docx') {
    const mammoth = require('mammoth');
    const result = await mammoth.extractRawText({ buffer });
    return result.value;
  }
  // For .doc, .txt and other text files, try as UTF-8 text
  return buffer.toString('utf-8');
};

// Try to parse a structured CSV directly without AI (e.g. Petpooja exports with known column headers)
// Returns { categories, menuItems } or null if not a recognized structured format
const tryParseStructuredCSV = (buffer, fileName) => {
  try {
    const XLSX = require('xlsx');
    const workbook = XLSX.read(buffer, { type: 'buffer' });
    const sheet = workbook.Sheets[workbook.SheetNames[0]];
    const rows = XLSX.utils.sheet_to_json(sheet, { defval: '' });
    if (!rows || rows.length === 0) return null;

    const headers = Object.keys(rows[0]).map(h => h.toLowerCase().trim());

    // Detect known column patterns
    const nameCol = headers.find(h => /^(product_?name|item_?name|name|dish_?name|menu_?item)$/i.test(h));
    const priceCol = headers.find(h => /^(product_?price|price|item_?price|rate|mrp)$/i.test(h));
    if (!nameCol || !priceCol) return null; // Not a structured menu CSV

    // Find original header names (case-preserving)
    const origHeaders = Object.keys(rows[0]);
    const findOrig = (lc) => origHeaders.find(h => h.toLowerCase().trim() === lc);
    const nameKey = findOrig(nameCol);
    const priceKey = findOrig(priceCol);
    const catCol = headers.find(h => /^(category_?name|category|type|group|section)$/i.test(h));
    const catKey = catCol ? findOrig(catCol) : null;

    // Detect variant columns (variant1_name, variant1_price, variant2_name, etc.)
    const variantSets = [];
    for (let i = 1; i <= 5; i++) {
      const vNameCol = origHeaders.find(h => new RegExp(`variant${i}[_]?name`, 'i').test(h));
      const vPriceCol = origHeaders.find(h => new RegExp(`variant${i}[_]?price`, 'i').test(h));
      if (vNameCol && vPriceCol) variantSets.push({ nameKey: vNameCol, priceKey: vPriceCol });
    }

    // Detect veg/non-veg heuristic keywords
    const nonVegKeywords = /chicken|mutton|fish|prawn|egg|lamb|pork|beef|meat|keema|gosht|surmai|pomfret|rawas|crab|lobster|shrimp|bacon|sausage|ham|salami|pepperoni/i;

    console.log(`📊 Structured CSV detected: ${rows.length} rows, name="${nameKey}", price="${priceKey}", category="${catKey || 'none'}", variants=${variantSets.length}`);

    const categoriesMap = new Map();
    const menuItems = [];
    let shortCode = 1;

    for (const row of rows) {
      const name = String(row[nameKey] || '').trim();
      if (!name) continue;

      const price = parseFloat(row[priceKey]) || 0;
      const categoryName = catKey ? String(row[catKey] || '').trim() : 'Other';

      // Collect categories
      if (categoryName && !categoriesMap.has(categoryName)) {
        categoriesMap.set(categoryName, { name: categoryName, order: categoriesMap.size + 1 });
      }

      // Collect variants from variant columns
      const variants = [];
      for (const vs of variantSets) {
        const vName = String(row[vs.nameKey] || '').trim();
        const vPrice = parseFloat(row[vs.priceKey]);
        if (vName && !isNaN(vPrice) && vPrice > 0) {
          variants.push({ name: vName, price: vPrice });
        }
      }

      // Determine isVeg
      const isVeg = !nonVegKeywords.test(name) && !nonVegKeywords.test(categoryName);

      // Generate imageKeyword
      const imageKeyword = name.toLowerCase().replace(/[^a-z0-9\s]/g, '').trim().split(/\s+/).slice(0, 3).join('-');

      menuItems.push({
        name,
        description: '',
        price,
        category: categoryName,
        isVeg,
        shortCode: String(shortCode++),
        variants,
        imageKeyword: imageKeyword || 'food-dish',
      });
    }

    console.log(`✅ Structured CSV parsed: ${menuItems.length} items, ${categoriesMap.size} categories`);
    return {
      categories: Array.from(categoriesMap.values()),
      menuItems,
    };
  } catch (err) {
    console.log('⚠️ Structured CSV parse failed, falling back to AI:', err.message);
    return null;
  }
};

// Extract menu from CSV/Excel. Downloads file, parses to text, sends to GPT-4o.
const extractMenuFromCSV = async (csvUrl, businessType = 'restaurant') => {
  try {
    console.log('📊 Extracting menu from CSV/Excel...');
    console.log('📥 Downloading file...');
    const buffer = await downloadFileBuffer(csvUrl);
    const fileName = csvUrl.split('/').pop().split('?')[0];

    // Try structured parsing first (fast, no AI cost, handles large files)
    const structured = tryParseStructuredCSV(buffer, fileName);
    if (structured && structured.menuItems.length > 0) {
      console.log(`✅ Used structured CSV parsing — ${structured.menuItems.length} items extracted without AI`);
      return structured;
    }

    const textContent = parseSpreadsheetToText(buffer, fileName);
    console.log(`📄 Parsed spreadsheet to text (${textContent.length} chars)`);

    if (!textContent.trim()) {
      console.log('⚠️ Empty spreadsheet');
      return { categories: [], menuItems: [] };
    }

    const response = await openai.chat.completions.create({
      model: "gpt-4o",
      messages: [
        {
          role: "user",
          content: `This is the content of a CSV/Excel file that may contain a restaurant menu:\n\n${textContent.substring(0, 30000)}\n\n1) If there is a Category/Type column, collect unique values as "categories":[{"name":"X","order":1},...]. If no category column, use "categories":[].
2) Extract ALL rows as menu items. For "category" use the row's Category/Type value if present, else "Other".
3) VARIANTS: If there are variant columns (variant1_name, variant1_price, variant2_name, variant2_price, etc.) OR if price column shows multiple values (e.g., "110/180", "Half/Full"), extract as "variants":[{"name":"Half","price":110},{"name":"Full","price":180}]. Otherwise use "variants":[].
4) For each item add "imageKeyword": a specific hyphen-separated keyword (1-3 words) that uniquely identifies this dish. Make each keyword DIFFERENT from similar items: "egg-thali" not "thali", "chicken-biryani" not "biryani", "masala-dosa" not "dosa", "chocolate-icecream" not "icecream", "chicken-burger" not "burger". Use the protein/variant as prefix (e.g. "mutton-thali", "veg-fried-rice", "strawberry-shake", "cheese-naan").
Return JSON: {"categories":[...],"menuItems":[{"name":"","description":"","price":0,"category":"...","isVeg":true,"shortCode":"1","variants":[],"imageKeyword":""}]}
shortCode: 1,2,3... If NOT a menu: {"categories":[],"menuItems":[]}`
        }
      ],
      max_tokens: 16000,
      temperature: 0.1
    });
    const content = response.choices[0].message.content;
    const jsonMatch = content.match(/\{[\s\S]*\}/);
    if (jsonMatch) {
      const d = JSON.parse(jsonMatch[0]);
      return { categories: Array.isArray(d.categories) ? d.categories : [], menuItems: Array.isArray(d.menuItems) ? d.menuItems : [] };
    }
    return { categories: [], menuItems: [] };
  } catch (error) {
    console.error('❌ CSV extraction failed:', error);
    return { categories: [], menuItems: [] };
  }
};

