// Role-based default page access for staff creation
// SYNC: This object is duplicated in 3 places — keep all in sync:
//   1. dine-backend/index.js (HERE — canonical source, used for staff creation)
//   2. dine-frontend/src/app/(dashboard)/admin/page.js (used for role change UI)
//   3. dine-app/components/StaffManagement.js (used for mobile staff management)
const ROLE_DEFAULT_PAGE_ACCESS = {
  admin:    { dashboard:true, history:true, tables:true, menu:true, analytics:true, inventory:true, kot:true, admin:{ settings:true, tax:true, pricing:true, payments:true, billingSettings:true, currency:true, print:true, features:true, restaurants:true, staff:true, orderManagement:true, offers:true, loyalty:true, googleReviews:true, whatsapp:true }, completeBill:true, invoice:true, customers:true, offers:true },
  manager:  { dashboard:true, history:true, tables:true, menu:true, analytics:true, inventory:{ read:true, add:true, update:true, delete:false }, kot:true, admin:false, completeBill:true, invoice:true, customers:true, offers:true },
  waiter:   { dashboard:true, history:true, tables:true, menu:true, analytics:false, inventory:false, kot:false, admin:false, completeBill:false, invoice:false, customers:false, offers:false },
  cashier:  { dashboard:true, history:true, tables:false, menu:true, analytics:false, inventory:false, kot:false, admin:false, completeBill:true, invoice:true, customers:false, offers:false },
  employee: { dashboard:true, history:true, tables:true, menu:true, analytics:false, inventory:false, kot:false, admin:false, completeBill:false, invoice:false, customers:false, offers:false },
  sales:    { dashboard:true, history:true, tables:false, menu:true, analytics:false, inventory:false, kot:false, admin:false, completeBill:false, invoice:false, customers:true, offers:true },
};

// Add new staff member
app.post('/api/staff/:restaurantId', authenticateToken, requireOwnerRole, async (req, res) => {
  try {
    const { restaurantId } = req.params;
    const { name, phone, email, role = 'waiter', startDate, address, username: usernameInput, pageAccess: requestedPageAccess } = req.body;

    if (!name || !phone) {
      return res.status(400).json({ error: 'Name and phone are required' });
    }

    // Only owner can create admin staff
    if (role === 'admin' && req.user.role !== 'owner') {
      return res.status(403).json({ error: 'Only the account owner can create admin staff.' });
    }
    // Cannot create owner role via staff API
    if (role === 'owner') {
      return res.status(400).json({ error: 'Cannot create owner role via staff API.' });
    }

    // Optional username: validate format and uniqueness (case-insensitive)
    let username = null;
    let usernameLower = null;
    if (usernameInput != null && String(usernameInput).trim() !== '') {
      const raw = String(usernameInput).trim();
      if (raw.length < 3 || raw.length > 50) {
        return res.status(400).json({ error: 'Username must be 3–50 characters' });
      }
      if (!/^[a-zA-Z0-9_]+$/.test(raw)) {
        return res.status(400).json({ error: 'Username can only contain letters, numbers and underscore' });
      }
      usernameLower = raw.toLowerCase();
      // Check username uniqueness in both staffUsers and users collections
      const existingInStaff = await db.collection(collections.staffUsers).where('usernameLower', '==', usernameLower).get();
      const existingInUsers = await db.collection(collections.users).where('usernameLower', '==', usernameLower).get();
      if (!existingInStaff.empty || !existingInUsers.empty) {
        return res.status(400).json({ error: 'Username already exists. Choose a different username.' });
      }
      username = raw;
    }


    // Check if email already exists in both collections (only if email is provided)
    if (email) {
      const existingInStaff = await db.collection(collections.staffUsers).where('email', '==', email).get();
      const existingInUsers = await db.collection(collections.users).where('email', '==', email).get();
      if (!existingInStaff.empty || !existingInUsers.empty) {
        return res.status(400).json({ error: 'Email already registered' });
      }
    }

    // Generate unique 5-digit numeric User ID (check both collections)
    let userId;
    let isUnique = false;
    while (!isUnique) {
      userId = Math.floor(10000 + Math.random() * 90000).toString(); // 5-digit number
      const existInStaff = await db.collection(collections.staffUsers).where('loginId', '==', userId).get();
      const existInUsers = await db.collection(collections.users).where('loginId', '==', userId).get();
      isUnique = existInStaff.empty && existInUsers.empty;
    }

    // Generate random password for staff
    const temporaryPassword = Math.random().toString(36).slice(-8);
    const hashedPassword = await bcrypt.hash(temporaryPassword, 10);

    const staffData = {
      name,
      phone,
      email: email || null,
      password: hashedPassword,
      role,
      restaurantId,
      address: address || null,
      status: 'active',
      startDate: startDate ? new Date(startDate) : new Date(),
      phoneVerified: false,
      emailVerified: false,
      provider: 'staff',
      createdAt: new Date(),
      updatedAt: new Date(),
      lastLogin: null,
      temporaryPassword: true, // Flag to indicate password needs to be changed
      loginId: userId, // Use the generated 5-digit numeric ID
      ...(username != null && { username, usernameLower }),
      // Use pageAccess from request if provided, otherwise use role-based defaults
      pageAccess: requestedPageAccess || ROLE_DEFAULT_PAGE_ACCESS[role] || {
        dashboard: true, history: true, tables: true, menu: true,
        analytics: false, inventory: false, kot: false, admin: false, completeBill: false
      }
    };

    const staffRef = await db.collection(collections.staffUsers).add(staffData);

    // Add to userRestaurants collection for access control
    await db.collection(collections.userRestaurants).add({
      userId: staffRef.id,
      restaurantId,
      role: role,
      pageAccess: staffData.pageAccess,
      createdAt: new Date(),
      updatedAt: new Date()
    });

    // Store temporary password for admin display (will be deleted after first login)
    await db.collection('staffCredentials').doc(staffRef.id).set({
      staffId: staffRef.id,
      loginId: userId,
      temporaryPassword: temporaryPassword,
      createdAt: new Date(),
      expiresAt: new Date(Date.now() + 7 * 24 * 60 * 60 * 1000) // 7 days
    });

    // TODO: Send email with login credentials
    console.log(`📧 Staff Login Credentials for ${name}:`);
    console.log(`   User ID: ${userId}`);
    console.log(`   Password: ${temporaryPassword}`);
    console.log(`   Restaurant: ${restaurantId}`);

    res.status(201).json({
      message: 'Staff member added successfully. Login credentials generated.',
      staff: {
        id: staffRef.id,
        name,
        phone,
        email: email || null,
        role,
        restaurantId,
        address,
        status: 'active',
        startDate: staffData.startDate,
        createdAt: staffData.createdAt,
        username: username || null
      },
      // For demo purposes, return credentials (remove in production)
      credentials: {
        loginId: userId,
        username: username || null,
        password: temporaryPassword
      }
    });

  } catch (error) {
    console.error('Add staff error:', error);
    res.status(500).json({ error: 'Failed to add staff member' });
  }
});

// Update staff member
app.patch('/api/staff/:staffId', authenticateToken, requireOwnerRole, async (req, res) => {
  try {
    const { staffId } = req.params;
    const { name, phone, email, role, status, pageAccess } = req.body;

    // Only owner can set role to admin
    if (role === 'admin' && req.user.role !== 'owner') {
      return res.status(403).json({ error: 'Only the account owner can assign admin role.' });
    }
    if (role === 'owner') {
      return res.status(400).json({ error: 'Cannot assign owner role to staff.' });
    }

    // Find staff in the correct collection
    const { doc: staffDoc, collection: staffColl } = await findStaffDoc(staffId);
    if (!staffDoc || !staffDoc.exists) {
      return res.status(404).json({ error: 'Staff member not found' });
    }

    const updateData = {
      updatedAt: new Date()
    };

    if (name) updateData.name = name;
    if (phone) updateData.phone = phone;
    if (email !== undefined) updateData.email = email;
    if (role) updateData.role = role;
    if (status) updateData.status = status;
    if (pageAccess) updateData.pageAccess = pageAccess;

    const collName = staffColl === 'staffUsers' ? collections.staffUsers : collections.users;
    await db.collection(collName).doc(staffId).update(updateData);

    // Invalidate user cache if status or role changed
    if (status || role) {
      invalidateUserCache(staffId);
    }

    res.json({ message: 'Staff member updated successfully' });

  } catch (error) {
    console.error('Update staff error:', error);
    res.status(500).json({ error: 'Failed to update staff member' });
  }
});

