// Get single KOT details
app.get('/api/kot/:restaurantId/:orderId', async (req, res) => {
  try {
    const { restaurantId, orderId } = req.params;

    const orderDoc = await db.collection(collections.orders).doc(orderId).get();

    if (!orderDoc.exists) {
      return res.status(404).json({ error: 'KOT not found' });
    }

    const orderData = { id: orderDoc.id, ...orderDoc.data() };

    if (orderData.restaurantId !== restaurantId) {
      return res.status(403).json({ error: 'Access denied to this KOT' });
    }

    // Get table information if exists
    let tableInfo = null;
    if (orderData.tableNumber) {
      try {
        const tablesSnapshot = await db.collection(collections.tables)
          .where('restaurantId', '==', restaurantId)
          .where('number', '==', orderData.tableNumber)
          .limit(1)
          .get();
        
        if (!tablesSnapshot.empty) {
          const tableData = tablesSnapshot.docs[0].data();
          tableInfo = {
            id: tablesSnapshot.docs[0].id,
            number: tableData.number,
            floor: tableData.floor,
            capacity: tableData.capacity
          };
        }
      } catch (error) {
        console.log('Table info fetch error:', error);
      }
    }

    const kotId = `KOT-${orderDoc.id.slice(-6).toUpperCase()}`;
    
    res.json({
      ...orderData,
      kotId,
      tableInfo,
      createdAt: orderData.createdAt?.toDate()?.toISOString() || new Date().toISOString(),
      updatedAt: orderData.updatedAt?.toDate()?.toISOString() || new Date().toISOString(),
      kotTime: orderData.kotTime?.toDate()?.toISOString() || orderData.createdAt?.toDate()?.toISOString(),
      cookingStartTime: orderData.cookingStartTime?.toDate()?.toISOString() || null,
      cookingEndTime: orderData.cookingEndTime?.toDate()?.toISOString() || null
    });

  } catch (error) {
    console.error('Get KOT details error:', error);
    res.status(500).json({ error: 'Failed to fetch KOT details' });
  }
});

// ============================================================================
// UNIFIED BILL / KOT RENDER ENDPOINTS
// ----------------------------------------------------------------------------
// Single source of truth for "ready-to-print" bill & KOT payloads.
// Consumed by: web (OrderSummary post-billing, orderhistory InvoiceModal),
//              electron dine-kot-printer, android dine-kot-printer-android.
// Guarantees visual + data parity across web preview and thermal print.
// Public (scope-checked by restaurantId param) so printer kiosks can use it.
// ============================================================================

const DEFAULT_PRINT_SETTINGS = {
  kotPrinterEnabled: true,
  manualPrintEnabled: true,
  showKOTSummaryAfterOrder: true,
  showBillSummaryAfterBilling: true,
  usePusherForKOT: false,
  autoPrintOnKOT: true,
  autoPrintOnBilling: false,
  autoPrintOnOnlineOrder: false,
  autoPrintOnTableCall: false,
  printKOTCopy: 1,
  printBillCopy: 1,
  billFontSize: 'medium',
  billFontScale: 100,
  billFontFamily: 'default'
};

// Business-type aware labels — mirrors the web InvoiceModal map so server can
// return the right wording once instead of every client duplicating it.
const BUSINESS_TYPE_LABELS = {
  restaurant: { title: 'TAX INVOICE',  billTo: 'Bill To',       itemCol: 'Item',    footer: 'Thank you for dining with us!' },
  bar:        { title: 'BAR BILL',     billTo: 'Customer',      itemCol: 'Drink',   footer: 'Drink responsibly. Thank you!' },
  bakery:     { title: 'BAKERY BILL',  billTo: 'Customer',      itemCol: 'Item',    footer: 'Thank you for your order!' },
  ice_cream:  { title: 'RECEIPT',      billTo: 'Customer',      itemCol: 'Item',    footer: 'Have a sweet day!' },
  cafe:       { title: 'CAFE RECEIPT', billTo: 'Customer',      itemCol: 'Item',    footer: 'Thank you! Visit again.' },
  qsr:        { title: 'RECEIPT',      billTo: 'Customer',      itemCol: 'Item',    footer: 'Thank you! Visit again.' }
};

const KOT_LABELS = {
  restaurant: { title: 'KITCHEN ORDER TICKET', footer: 'Please prepare ASAP' },
  bar:        { title: 'BAR ORDER',            footer: 'Please prepare ASAP' },
  bakery:     { title: 'BAKERY ORDER',         footer: 'Please prepare ASAP' },
  ice_cream:  { title: 'ORDER TICKET',         footer: 'Please prepare ASAP' },
  cafe:       { title: 'CAFE ORDER',           footer: 'Please prepare ASAP' },
  qsr:        { title: 'ORDER TICKET',         footer: 'Please prepare ASAP' }
};

const toIsoOrNull = (v) => {
  if (!v) return null;
  if (v instanceof Date) return v.toISOString();
  if (typeof v === 'string') return v;
  if (typeof v?.toDate === 'function') return v.toDate().toISOString();
  return null;
};

const formatIST = (iso) => {
  const d = iso ? new Date(iso) : new Date();
  const formattedTime = d.toLocaleTimeString('en-IN', {
    hour: '2-digit', minute: '2-digit', hour12: true, timeZone: 'Asia/Kolkata'
  });
  const formattedDate = d.toLocaleDateString('en-IN', {
    day: '2-digit', month: 'short', year: 'numeric', timeZone: 'Asia/Kolkata'
  });
  return { formattedDate, formattedTime };
};

const r2 = (n) => Math.round((Number(n) || 0) * 100) / 100;

const buildRestaurantBlock = (restaurantId, data) => ({
  id: restaurantId,
  name: data.name || 'Restaurant',
  legalBusinessName: data.legalBusinessName || '',
  address: data.address || '',
  city: data.city || '',
  phone: data.phone || '',
  email: data.email || '',
  gstin: data.gstin || '',
  fssai: data.fssai || '',
  showGstOnInvoice: data.showGstOnInvoice === true,
  showFssaiOnInvoice: data.showFssaiOnInvoice === true,
  // International identity fields
  vatNumber: data.vatNumber || '',
  taxId: data.taxId || '',
  businessRegistrationNumber: data.businessRegistrationNumber || '',
  showTaxIdOnInvoice: data.showTaxIdOnInvoice === true,
  countryCode: data.currencySettings?.countryCode || data.countryCode || 'IN',
  businessType: data.businessType || 'restaurant',
  cuisine: data.cuisine || '',
  logo: data.logo || '',
  tagline: data.tagline || '',
  upiId: data.upiId || '',
  currency: data.currency || 'INR',
  currencySymbol: data.currencySymbol || (data.currency === 'USD' ? '$' : '₹')
});

// Build the full bill render payload from order + restaurant docs.
// Returned shape is a SUPERSET of the legacy POST /api/invoice/generate
// response — all `invoice.*` fields exist at the top level AND inside
// `bill.*`, so existing web code that reads `invoice.restaurantName` etc.
// continues to work when pointed at this endpoint.
const assembleBillRenderPayload = (orderId, orderData, restaurantId, restaurantData) => {
  const taxSettings = restaurantData.taxSettings || {
    enabled: true,
    taxes: [{ id: 'gst', name: 'GST', rate: 5, enabled: true, type: 'percentage' }],
    defaultTaxRate: 5
  };

  const itemsSubtotal = (orderData.items || [])
    .reduce((sum, it) => sum + ((it.price || 0) * (it.quantity || 1)), 0);
  const subtotal = r2(orderData.subtotal || itemsSubtotal);

  const discountAmount = r2(orderData.discountAmount);
  const manualDiscount = r2(orderData.manualDiscount);
  const loyaltyDiscount = r2(orderData.loyaltyDiscount);
  const totalDiscount = r2(discountAmount + manualDiscount + loyaltyDiscount);

  let totalTax = 0;
  let taxBreakdown = [];
  if (Array.isArray(orderData.taxBreakdown) && orderData.taxBreakdown.length > 0) {
    taxBreakdown = orderData.taxBreakdown;
    totalTax = r2(orderData.taxAmount || taxBreakdown.reduce((s, t) => s + (t.amount || 0), 0));
  } else if (taxSettings.enabled) {
    const taxable = Math.max(0, subtotal - totalDiscount);
    for (const tax of (taxSettings.taxes || [])) {
      if (tax.enabled) {
        const amt = (taxable * (tax.rate || 0)) / 100;
        taxBreakdown.push({ id: tax.id, name: tax.name, rate: tax.rate, amount: r2(amt) });
        totalTax += amt;
      }
    }
    totalTax = r2(totalTax);
  }

  const serviceChargeAmount = orderData.serviceChargeAmount ? r2(orderData.serviceChargeAmount) : null;
  const tipAmount           = orderData.tipAmount ? r2(orderData.tipAmount) : null;
  const roundOffAmount      = orderData.roundOffAmount != null ? r2(orderData.roundOffAmount) : null;

  const grandTotal = r2(
    orderData.finalAmount ||
    (subtotal - totalDiscount + totalTax + (serviceChargeAmount || 0) + (tipAmount || 0) + (roundOffAmount || 0))
  );

  const createdAtIso   = toIsoOrNull(orderData.createdAt);
  const completedAtIso = toIsoOrNull(orderData.completedAt);
  const { formattedDate, formattedTime } = formatIST(completedAtIso || createdAtIso);

  const printSettings = { ...DEFAULT_PRINT_SETTINGS, ...(restaurantData.printSettings || {}) };
  const businessType = restaurantData.businessType || 'restaurant';
  const labels = BUSINESS_TYPE_LABELS[businessType] || BUSINESS_TYPE_LABELS.restaurant;

  const restaurant = buildRestaurantBlock(restaurantId, restaurantData);

  // Legacy-compatible flat invoice fields (used by existing web OrderSummary)
  const flat = {
    id: orderData.invoiceId || null,
    orderId,
    dailyOrderId: orderData.dailyOrderId || null,
    orderNumber: orderData.orderNumber || null,
    restaurantId,
    restaurantName: restaurant.name,
    restaurantLegalName: restaurant.legalBusinessName || '',
    restaurantAddress: restaurant.address,
    restaurantPhone: restaurant.phone,
    restaurantEmail: restaurant.email,
    gstin: restaurant.gstin || '',
    fssai: restaurant.fssai || '',
    showGstOnInvoice: restaurant.showGstOnInvoice === true,
    showFssaiOnInvoice: restaurant.showFssaiOnInvoice === true,
    vatNumber: restaurant.vatNumber || '',
    taxId: restaurant.taxId || '',
    businessRegistrationNumber: restaurant.businessRegistrationNumber || '',
    showTaxIdOnInvoice: restaurant.showTaxIdOnInvoice === true,
    countryCode: restaurant.countryCode || 'IN',
    customerName: orderData.customerInfo?.name || orderData.customerName || 'Walk-in Customer',
    customerPhone: orderData.customerInfo?.phone || orderData.customerMobile || '',
    customerEmail: orderData.customerInfo?.email || '',
    tableNumber: orderData.tableNumber || '',
    roomNumber: orderData.roomNumber || '',
    orderType: orderData.orderType || 'dine-in',
    items: orderData.items || [],
    subtotal,
    discountAmount,
    manualDiscount,
    loyaltyDiscount,
    totalDiscount,
    appliedOffer: orderData.appliedOffer || (orderData.selectedOfferName ? { name: orderData.selectedOfferName } : null),
    appliedOffers: orderData.appliedOffers || null,
    selectedOfferName: orderData.selectedOfferName || null,
    taxBreakdown,
    totalTax,
    taxAmount: totalTax,
    grandTotal,
    finalAmount: grandTotal,
    totalAmount: r2(orderData.totalAmount || (subtotal - totalDiscount)),
    paymentMethod: orderData.paymentMethod || 'cash',
    serviceChargeRate: orderData.serviceChargeRate || null,
    serviceChargeAmount,
    tipAmount,
    tipPercentage: orderData.tipPercentage || null,
    roundOffAmount,
    splitPayments: orderData.splitPayments || null,
    cashReceived: orderData.cashReceived ? r2(orderData.cashReceived) : null,
    changeReturned: orderData.changeReturned ? r2(orderData.changeReturned) : null,
    paidAmount: orderData.paidAmount ? r2(orderData.paidAmount) : null,
    outstandingAmount: orderData.outstandingAmount ? r2(orderData.outstandingAmount) : null,
    notes: orderData.notes || '',
    specialInstructions: orderData.specialInstructions || '',
    staffInfo: orderData.staffInfo || null,
    status: orderData.status || null,
    createdAt: createdAtIso,
    completedAt: completedAtIso,
    invoiceDate: completedAtIso || createdAtIso,
    generatedAt: new Date().toISOString(),
    formattedDate,
    formattedTime
  };

  return {
    success: true,
    restaurant,
    printSettings,
    labels,
    bill: flat,
    // Legacy compatibility: also expose at top level so existing web code
    // treating the response as `invoice` continues to work unchanged.
    invoice: flat
  };
};

// GET /api/bill/render/:restaurantId/:orderId
// Public, scope-checked. Returns unified ready-to-print bill payload.
// Used by web bill summary, electron + android thermal printers.
app.get('/api/bill/render/:restaurantId/:orderId', async (req, res) => {
  try {
    const { restaurantId, orderId } = req.params;

    const [orderDoc, restaurantDoc] = await Promise.all([
      db.collection(collections.orders).doc(orderId).get(),
      db.collection(collections.restaurants).doc(restaurantId).get()
    ]);

    if (!orderDoc.exists) return res.status(404).json({ error: 'Order not found' });
    if (!restaurantDoc.exists) return res.status(404).json({ error: 'Restaurant not found' });

    const orderData = orderDoc.data();
    if (orderData.restaurantId !== restaurantId) {
      return res.status(403).json({ error: 'Access denied to this order' });
    }

    const payload = assembleBillRenderPayload(orderDoc.id, orderData, restaurantId, restaurantDoc.data());
    res.json(payload);
  } catch (error) {
    console.error('Bill render error:', error);
    res.status(500).json({ error: 'Failed to render bill' });
  }
});

// GET /api/kot/render/:restaurantId/:orderId
// Public, scope-checked. Returns unified ready-to-print KOT payload.
app.get('/api/kot/render/:restaurantId/:orderId', async (req, res) => {
  try {
    const { restaurantId, orderId } = req.params;

    const [orderDoc, restaurantDoc] = await Promise.all([
      db.collection(collections.orders).doc(orderId).get(),
      db.collection(collections.restaurants).doc(restaurantId).get()
    ]);

    if (!orderDoc.exists) return res.status(404).json({ error: 'Order not found' });
    if (!restaurantDoc.exists) return res.status(404).json({ error: 'Restaurant not found' });

    const orderData = orderDoc.data();
    if (orderData.restaurantId !== restaurantId) {
      return res.status(403).json({ error: 'Access denied to this order' });
    }

    const restaurantData = restaurantDoc.data();
    const createdAtIso = toIsoOrNull(orderData.createdAt);
    const { formattedDate, formattedTime } = formatIST(createdAtIso);
    const printSettings = { ...DEFAULT_PRINT_SETTINGS, ...(restaurantData.printSettings || {}) };
    const businessType = restaurantData.businessType || 'restaurant';
    const labels = KOT_LABELS[businessType] || KOT_LABELS.restaurant;
    const restaurant = buildRestaurantBlock(restaurantId, restaurantData);
    const kotId = `KOT-${orderDoc.id.slice(-6).toUpperCase()}`;

    res.json({
      success: true,
      restaurant,
      printSettings,
      labels,
      kot: {
        id: orderDoc.id,
        orderId: orderDoc.id,
        kotId,
        dailyOrderId: orderData.dailyOrderId || null,
        orderNumber: orderData.orderNumber || null,
        tableNumber: orderData.tableNumber || '',
        roomNumber: orderData.roomNumber || '',
        orderType: orderData.orderType || 'dine-in',
        items: orderData.items || [],
        notes: orderData.notes || '',
        specialInstructions: orderData.specialInstructions || '',
        staffInfo: orderData.staffInfo || null,
        createdAt: createdAtIso,
        formattedDate,
        formattedTime,
        isReprint: orderData.kotPrinted === true
      }
    });
  } catch (error) {
    console.error('KOT render error:', error);
    res.status(500).json({ error: 'Failed to render KOT' });
  }
});

// Cancel Order API
app.patch('/api/orders/:orderId/cancel', authenticateToken, async (req, res) => {
  try {
    // Granular permission check: orders.cancel
    if (!(await checkFeaturePermission(req, 'orders', 'cancel'))) {
      return res.status(403).json({ error: 'Access denied. Orders cancel permission required.' });
    }
    const { orderId } = req.params;
    const { reason } = req.body;

    console.log(`🚫 Cancel Order API - Order: ${orderId}, Reason: ${reason || 'No reason provided'}`);

    // Get the order
    const orderDoc = await db.collection(collections.orders).doc(orderId).get();
    if (!orderDoc.exists) {
      return res.status(404).json({ error: 'Order not found' });
    }

    const orderData = orderDoc.data();

    // Check if order can be cancelled (not completed billing)
    if (orderData.status === 'completed' || orderData.paymentStatus === 'completed') {
      return res.status(400).json({ 
        error: 'Cannot cancel order that has been completed or billed' 
      });
    }

    // Check if order is already cancelled
    if (orderData.status === 'cancelled') {
      return res.status(400).json({ 
        error: 'Order is already cancelled' 
      });
    }

    // Update order status to cancelled
    const updateData = {
      status: 'cancelled',
      cancelledAt: new Date(),
      cancelledBy: req.user.userId,
      cancellationReason: reason || 'No reason provided',
      updatedAt: new Date()
    };

    await db.collection(collections.orders).doc(orderId).update(updateData);

    // Update daily analytics stats — only if order was counted (not saved)
    if (!['saved', 'cancelled', 'deleted'].includes(orderData.status)) {
      updateDailyStats(orderData.restaurantId, orderData, 'cancel');
    }

    // If order has a table, update table status
    if (orderData.tableNumber) {
      try {
        const tablesSnapshot = await db.collection(collections.tables)
          .where('restaurantId', '==', orderData.restaurantId)
          .where('number', '==', orderData.tableNumber)
          .limit(1)
          .get();

        if (!tablesSnapshot.empty) {
          await db.collection(collections.tables).doc(tablesSnapshot.docs[0].id).update({
            status: 'available',
            currentOrderId: null,
            updatedAt: new Date()
          });
          console.log(`🔄 Updated table ${orderData.tableNumber} to available after order cancellation`);
        }
      } catch (error) {
        console.error('Error updating table status after cancellation:', error);
      }
    }

    console.log(`✅ Order ${orderId} cancelled successfully`);

    res.json({
      success: true,
      message: 'Order cancelled successfully',
      orderId: orderId,
      cancelledAt: updateData.cancelledAt
    });

  } catch (error) {
    console.error('Cancel order error:', error);
    res.status(500).json({ error: 'Failed to cancel order' });
  }
});

// ========================================
// FCM (Firebase Cloud Messaging) — Printer device token registration
// ========================================
// These endpoints let printer clients (Android/Electron) register their FCM
// token so the server can fan out KOT/Bill print events as data messages
// alongside (or instead of) Pusher. See services/fcmService.js for details.
const fcmService = require('./services/fcmService');

app.post('/api/printer/register-fcm-token', async (req, res) => {
  try {
    const { restaurantId, deviceId, token, deviceType, deviceName } = req.body || {};
    if (!restaurantId || !deviceId || !token) {
      return res.status(400).json({ success: false, error: 'restaurantId, deviceId and token are required' });
    }
    await fcmService.registerToken({ restaurantId, deviceId, token, deviceType, deviceName });
    res.json({ success: true });
  } catch (error) {
    console.error('FCM register error:', error);
    res.status(500).json({ success: false, error: error.message });
  }
});

app.post('/api/printer/unregister-fcm-token', async (req, res) => {
  try {
    const { restaurantId, deviceId } = req.body || {};
    if (!restaurantId || !deviceId) {
      return res.status(400).json({ success: false, error: 'restaurantId and deviceId are required' });
    }
    await fcmService.unregisterToken({ restaurantId, deviceId });
    res.json({ success: true });
  } catch (error) {
    console.error('FCM unregister error:', error);
    res.status(500).json({ success: false, error: error.message });
  }
});

// ========================================
// VOICE ASSISTANT API
// ========================================

// Process voice order using ChatGPT
app.post('/api/voice/process-order', authenticateToken, aiUsageLimiter.middleware(), async (req, res) => {
  try {
    const { transcript, restaurantId } = req.body;
    
    if (!transcript || !restaurantId) {
      return res.status(400).json({ error: 'Transcript and restaurantId are required' });
    }

    console.log('🎤 Voice order processing:', { transcript, restaurantId });

    // Get menu items from restaurant document (menu is stored in restaurant.menu.items)
    const restaurantDoc = await db.collection(collections.restaurants).doc(restaurantId).get();
    
    if (!restaurantDoc.exists) {
      return res.status(404).json({ error: 'Restaurant not found' });
    }

    const restaurantData = restaurantDoc.data();
    const menuData = restaurantData.menu || { categories: [], items: [] };
    let menuItems = menuData.items || [];

    // Filter only active items
    menuItems = menuItems.filter(item => item.status === 'active' || item.active === true);

    if (menuItems.length === 0) {
      return res.status(404).json({ error: 'No menu items found' });
    }

    // Create menu context for ChatGPT
    const menuContext = menuItems.map(item => 
      `- ${item.name} (₹${item.price}) - ID: ${item.id}`
    ).join('\n');

    // Use ChatGPT to parse the voice command
    const openai = new OpenAI({
      apiKey: process.env.OPENAI_API_KEY
    });

    const completion = await openai.chat.completions.create({
      model: "gpt-4o-mini",
      messages: [
        {
          role: "system",
          content: `You are a restaurant order assistant for Indian cuisine. Parse the user's voice command with Indian accents and extract menu items with quantities.
          
Available menu items:
${menuContext}

Instructions:
1. Understand Indian accent variations (e.g., "paneer" as "paneer" or "panir"; "chhole" as "chhole", "chole", "chhola")
2. Extract all mentioned menu items and their quantities
3. Match items using phonetic similarity and common variations
4. Be flexible with spelling and pronunciation
5. Return ONLY valid menu items that exist in the list
6. Extract quantity (default is 1 if not specified)
7. Return as a JSON array of objects with: id, name, quantity

Example responses:
- "Add 2 samosas" → [{"id":"item123","name":"Samosa","quantity":2}]
- "I want one Paneer Tikka and two Chhole Bhature" → [{"id":"item456","name":"Paneer Tikka","quantity":1},{"id":"item789","name":"Cholle Bhature","quantity":2}]
- "Give me one Panir tika and one Chole Bhatura" → [{"id":"item456","name":"Paneer Tikka","quantity":1},{"id":"item789","name":"Cholle Bhature","quantity":1}]`
        },
        {
          role: "user",
          content: transcript
        }
      ],
      temperature: 0.2,
      max_tokens: 300
    });

    const responseText = completion.choices[0].message.content.trim();
    console.log('🤖 ChatGPT response:', responseText);

    // Parse the response (might be JSON or markdown code block)
    let parsedItems;
    try {
      // Try to extract JSON from markdown code block
      const jsonMatch = responseText.match(/```json\s*([\s\S]*?)\s*```/) || responseText.match(/```\s*([\s\S]*?)\s*```/);
      if (jsonMatch) {
        parsedItems = JSON.parse(jsonMatch[1]);
      } else {
        parsedItems = JSON.parse(responseText);
      }
    } catch (parseError) {
      console.error('Failed to parse ChatGPT response:', responseText);
      return res.status(500).json({ error: 'Failed to parse voice command' });
    }

    // Helper function for fuzzy name matching
    const fuzzyMatch = (name1, name2) => {
      const n1 = name1.toLowerCase().replace(/[^a-z0-9]/g, '');
      const n2 = name2.toLowerCase().replace(/[^a-z0-9]/g, '');
      return n1.includes(n2) || n2.includes(n1);
    };

    // Validate and enrich items with prices
    const enrichedItems = [];
    for (const item of parsedItems) {
      // First try exact match by name
      let menuItem = menuItems.find(m => m.name.toLowerCase() === item.name.toLowerCase());
      
      // If not found, try fuzzy matching
      if (!menuItem) {
        menuItem = menuItems.find(m => fuzzyMatch(m.name, item.name));
      }
      
      // If still not found, try to match by id if provided
      if (!menuItem && item.id) {
        menuItem = menuItems.find(m => m.id === item.id);
      }
      
      if (!menuItem) {
        console.log(`⚠️ Could not match item: ${item.name}`);
        continue; // Skip items that don't match
      }
      
      enrichedItems.push({
        id: menuItem.id,
        name: menuItem.name,
        price: menuItem.price,
        quantity: item.quantity || 1
      });
    }

    if (enrichedItems.length === 0) {
      return res.status(404).json({ error: 'Could not match any menu items' });
    }

    console.log('✅ Voice order parsed:', enrichedItems);

    res.json({
      success: true,
      items: enrichedItems
    });

  } catch (error) {
    console.error('Voice processing error:', error);
    res.status(500).json({
      error: 'Failed to process voice command',
      message: error.message
    });
  }
});

// Smart Voice Order Processing - Streaming with Intent Detection
app.post('/api/voice/smart-process', authenticateToken, aiUsageLimiter.middleware(), async (req, res) => {
  try {
    const {
      transcript,
      restaurantId,
      existingCart = [],
      processedItemIds = [],
      isStreaming = true
    } = req.body;

    if (!transcript || !restaurantId) {
      return res.status(400).json({ error: 'Transcript and restaurantId are required' });
    }

    console.log('🎤 Smart voice processing:', {
      transcript: transcript.substring(0, 100),
      cartItems: existingCart.length,
      processedCount: processedItemIds.length
    });

    // Get menu items from restaurant
    const restaurantDoc = await db.collection(collections.restaurants).doc(restaurantId).get();

    if (!restaurantDoc.exists) {
      return res.status(404).json({ error: 'Restaurant not found' });
    }

    const restaurantData = restaurantDoc.data();
    const menuData = restaurantData.menu || { categories: [], items: [] };
    let menuItems = menuData.items || [];

    // Filter only active items
    menuItems = menuItems.filter(item => item.status === 'active' || item.active === true);

    if (menuItems.length === 0) {
      return res.status(404).json({ error: 'No menu items found' });
    }

    // Create menu context
    const menuContext = menuItems.slice(0, 100).map(item =>
      `${item.name} (₹${item.price}) [ID:${item.id}]`
    ).join(', ');

    // Create cart context
    const cartContext = existingCart.length > 0
      ? `Current cart: ${existingCart.map(i => `${i.quantity}x ${i.name}`).join(', ')}`
      : 'Cart is empty';

    const openai = new OpenAI({
      apiKey: process.env.OPENAI_API_KEY
    });

    const systemPrompt = `You are a smart restaurant voice order assistant. Parse voice commands and detect user intent.

MENU: ${menuContext}

${cartContext}

RESPOND WITH JSON ONLY:
{
  "items": [{"id":"item_id", "name":"Item Name", "quantity":1, "action":"add"}],
  "compiledText": "1 Paneer Tikka, 2 Dosa",
  "shouldStop": false,
  "intent": "adding"
}

RULES:
1. Parse Indian accents (paneer/panir, chhole/chole, dosa/dhosa)
2. Match items phonetically with menu
3. Detect quantities (ek=1, do=2, teen=3, char=4, paanch=5)
4. "action" can be: "add", "remove", "update"
5. "shouldStop" = true if user says: "that's all", "bas", "ho gaya", "done", "order kar do", "ye sab", "baki nahi", "complete", "finish"
6. "compiledText" = human readable summary of recognized items
7. "intent": "adding" (new items), "modifying" (changing cart), "completing" (ready to place order)
8. If user says "hata do", "remove", "cancel" for an item, set action="remove"
9. Only return NEW items not in processedItemIds: [${processedItemIds.join(',')}]`;

    const completion = await openai.chat.completions.create({
      model: "gpt-4o-mini",
      messages: [
        { role: "system", content: systemPrompt },
        { role: "user", content: transcript }
      ],
      temperature: 0.1,
      max_tokens: 400
    });

    const responseText = completion.choices[0].message.content.trim();
    console.log('🤖 Smart response:', responseText);

    // Parse the response
    let result = { items: [], compiledText: '', shouldStop: false, intent: 'adding' };
    try {
      const jsonMatch = responseText.match(/```json\s*([\s\S]*?)\s*```/) ||
                        responseText.match(/```\s*([\s\S]*?)\s*```/) ||
                        [null, responseText];
      result = JSON.parse(jsonMatch[1] || responseText);
    } catch (parseError) {
      console.log('Parse error, using defaults');
    }

    // Helper for fuzzy matching
    const fuzzyMatch = (name1, name2) => {
      const n1 = (name1 || '').toLowerCase().replace(/[^a-z0-9]/g, '');
      const n2 = (name2 || '').toLowerCase().replace(/[^a-z0-9]/g, '');
      return n1.includes(n2) || n2.includes(n1) ||
             n1.split('').filter(c => n2.includes(c)).length > Math.min(n1.length, n2.length) * 0.6;
    };

    // Validate and enrich items
    const validItems = [];
    for (const item of (result.items || [])) {
      let menuItem = menuItems.find(m => m.id === item.id) ||
                     menuItems.find(m => m.name.toLowerCase() === (item.name || '').toLowerCase()) ||
                     menuItems.find(m => fuzzyMatch(m.name, item.name));

      if (!menuItem) continue;

      // Skip already processed unless it's a remove/update action
      if (processedItemIds.includes(menuItem.id) && item.action === 'add') {
        continue;
      }

      validItems.push({
        id: menuItem.id,
        name: menuItem.name,
        price: menuItem.price,
        quantity: item.quantity || 1,
        action: item.action || 'add',
        image: menuItem.image || null
      });
    }

    console.log(`✅ Smart processed: ${validItems.length} items, shouldStop: ${result.shouldStop}`);

    res.json({
      success: true,
      items: validItems,
      compiledText: result.compiledText || '',
      shouldStop: result.shouldStop || false,
      intent: result.intent || 'adding',
      allProcessedIds: [...processedItemIds, ...validItems.filter(i => i.action === 'add').map(i => i.id)]
    });

  } catch (error) {
    console.error('Smart voice processing error:', error);
    res.status(500).json({
      error: 'Failed to process voice command',
      message: error.message
    });
  }
});

