// GET - Expiry alerts (batches expiring soon + already expired)
app.get('/api/inventory/:restaurantId/expiry-alerts', authenticateToken, async (req, res) => {
  try {
    const { restaurantId } = req.params;
    const { days } = req.query;
    const alertDays = parseInt(days) || 7;

    const batchesSnap = await db.collection(collections.stockBatches)
      .where('restaurantId', '==', restaurantId)
      .where('status', '==', 'active')
      .get();

    const now = new Date();
    const alertDate = new Date(now);
    alertDate.setDate(alertDate.getDate() + alertDays);

    const expired = [];
    const expiringSoon = [];

    batchesSnap.forEach(doc => {
      const data = doc.data();
      const expiryDate = data.expiryDate?.toDate?.() || (data.expiryDate ? new Date(data.expiryDate) : null);
      if (!expiryDate) return;
      if ((data.remainingQty || 0) <= 0) return;

      const entry = {
        id: doc.id,
        ...data,
        expiryDate,
        mfgDate: data.mfgDate?.toDate?.() || data.mfgDate || null,
        daysUntilExpiry: Math.ceil((expiryDate - now) / (1000 * 60 * 60 * 24)),
        wasteValue: (data.remainingQty || 0) * (data.costPerUnit || 0)
      };

      if (expiryDate < now) {
        expired.push(entry);
      } else if (expiryDate <= alertDate) {
        expiringSoon.push(entry);
      }
    });

    expired.sort((a, b) => a.expiryDate - b.expiryDate);
    expiringSoon.sort((a, b) => a.expiryDate - b.expiryDate);

    const totalExpiredValue = expired.reduce((s, e) => s + (e.wasteValue || 0), 0);
    const totalExpiringValue = expiringSoon.reduce((s, e) => s + (e.wasteValue || 0), 0);

    res.json({
      expired,
      expiringSoon,
      summary: {
        expiredCount: expired.length,
        expiringCount: expiringSoon.length,
        totalExpiredValue,
        totalExpiringValue,
        alertDays
      }
    });
  } catch (error) {
    console.error('Get expiry alerts error:', error);
    res.status(500).json({ error: 'Failed to fetch expiry alerts' });
  }
});

// GET - Aggregated waste summary dashboard
app.get('/api/inventory/:restaurantId/waste-summary', authenticateToken, async (req, res) => {
  try {
    const { restaurantId } = req.params;

    const snapshot = await db.collection(collections.wasteEntries)
      .where('restaurantId', '==', restaurantId)
      .get();

    const now = new Date();
    const todayStart = new Date(now); todayStart.setHours(0, 0, 0, 0);
    const weekStart = new Date(now); weekStart.setDate(weekStart.getDate() - 7);
    const monthStart = new Date(now.getFullYear(), now.getMonth(), 1);

    let todayValue = 0, weekValue = 0, monthValue = 0, allTimeValue = 0;
    let todayQty = 0, weekQty = 0, monthQty = 0;
    const reasonTotals = {};
    const sourceTotals = {};
    const itemTotals = {};
    const dailyTrend = {}; // last 7 days

    snapshot.forEach(doc => {
      const data = doc.data();
      const entryDate = data.date?.toDate?.() || data.createdAt?.toDate?.() || (data.date ? new Date(data.date) : data.createdAt ? new Date(data.createdAt) : null);
      if (!entryDate) return;

      const val = data.wasteValue || data.totalCost || 0;
      const qty = data.quantity || 0;
      allTimeValue += val;

      if (entryDate >= todayStart) { todayValue += val; todayQty += qty; }
      if (entryDate >= weekStart) { weekValue += val; weekQty += qty; }
      if (entryDate >= monthStart) { monthValue += val; monthQty += qty; }

      // Reason breakdown
      reasonTotals[data.reason] = (reasonTotals[data.reason] || 0) + val;
      // Source breakdown
      sourceTotals[data.source] = (sourceTotals[data.source] || 0) + val;
      // Top wasted items
      if (!itemTotals[data.itemId]) {
        itemTotals[data.itemId] = { itemId: data.itemId, itemName: data.itemName, totalValue: 0, totalQty: 0, unit: data.unit };
      }
      itemTotals[data.itemId].totalValue += val;
      itemTotals[data.itemId].totalQty += qty;

      // Daily trend (last 7 days)
      if (entryDate >= weekStart) {
        const dayKey = entryDate.toISOString().split('T')[0];
        dailyTrend[dayKey] = (dailyTrend[dayKey] || 0) + val;
      }
    });

    // Fill in missing days for trend
    const trend = [];
    for (let i = 6; i >= 0; i--) {
      const d = new Date(now);
      d.setDate(d.getDate() - i);
      const key = d.toISOString().split('T')[0];
      trend.push({ date: key, value: dailyTrend[key] || 0 });
    }

    const topItems = Object.values(itemTotals).sort((a, b) => b.totalValue - a.totalValue).slice(0, 10);

    res.json({
      today: { value: todayValue, qty: todayQty },
      week: { value: weekValue, qty: weekQty },
      month: { value: monthValue, qty: monthQty },
      allTime: { value: allTimeValue },
      reasonBreakdown: reasonTotals,
      sourceBreakdown: sourceTotals,
      topItems,
      trend,
      totalEntries: snapshot.size
    });
  } catch (error) {
    console.error('Get waste summary error:', error);
    res.status(500).json({ error: 'Failed to fetch waste summary' });
  }
});

// POST - Mark an expired batch as waste (auto-expiry detection)
app.post('/api/inventory/:restaurantId/mark-expired-waste', authenticateToken, async (req, res) => {
  try {
    const { restaurantId } = req.params;
    const { userId } = req.user;
    const { batchId } = req.body;

    if (!batchId) return res.status(400).json({ error: 'batchId is required' });

    const batchDoc = await db.collection(collections.stockBatches).doc(batchId).get();
    if (!batchDoc.exists || batchDoc.data().restaurantId !== restaurantId) {
      return res.status(404).json({ error: 'Batch not found' });
    }

    const batch = batchDoc.data();
    if ((batch.remainingQty || 0) <= 0) {
      return res.status(400).json({ error: 'Batch already depleted' });
    }

    const wasteQty = batch.remainingQty;
    const wasteValue = wasteQty * (batch.costPerUnit || 0);

    // Mark batch as depleted
    await db.collection(collections.stockBatches).doc(batchId).update({
      remainingQty: 0, status: 'depleted', updatedAt: new Date()
    });

    // Deduct from inventory item
    const itemDoc = await db.collection(collections.inventory).doc(batch.inventoryItemId).get();
    if (itemDoc.exists) {
      const itemData = itemDoc.data();
      const oldStock = itemData.currentStock || 0;
      const newStock = Math.max(0, oldStock - wasteQty);
      await db.collection(collections.inventory).doc(batch.inventoryItemId).update({
        currentStock: newStock,
        wastedQty: (itemData.wastedQty || 0) + wasteQty,
        lastUpdated: new Date()
      });

      await db.collection(collections.inventoryTransactions).add({
        restaurantId, inventoryItemId: batch.inventoryItemId,
        inventoryItemName: batch.inventoryItemName || '',
        type: 'WASTE', source: 'EXPIRY',
        quantityChange: -wasteQty, previousStock: oldStock, newStock,
        unit: batch.unit || '', date: new Date(), performedBy: userId,
        notes: `Expired batch marked as waste (batch ${batchId})`
      });
    }

    // Create waste entry
    await db.collection(collections.wasteEntries).add({
      restaurantId, itemId: batch.inventoryItemId,
      itemName: batch.inventoryItemName || '',
      quantity: wasteQty, unit: batch.unit || '',
      reason: 'expired', source: 'EXPIRY',
      costPerUnit: batch.costPerUnit || 0, wasteValue,
      notes: `Auto-detected expired batch`, batchId,
      recordedBy: userId, date: new Date(), createdAt: new Date()
    });

    res.json({ success: true, wasteQty, wasteValue, itemName: batch.inventoryItemName });
  } catch (error) {
    console.error('Mark expired waste error:', error);
    res.status(500).json({ error: 'Failed to mark expired waste' });
  }
});

// POST - AI analyze leftover food → map to recipe ingredients
app.post('/api/inventory/:restaurantId/analyze-leftovers', authenticateToken, aiUsageLimiter.middleware(), async (req, res) => {
  try {
    const { restaurantId } = req.params;
    const { text } = req.body;

    if (!text || !text.trim()) {
      return res.status(400).json({ error: 'text describing leftovers is required' });
    }

    // Load restaurant's recipes
    const recipesSnap = await db.collection(collections.recipes)
      .where('restaurantId', '==', restaurantId).get();
    const recipes = [];
    recipesSnap.forEach(doc => recipes.push({ id: doc.id, ...doc.data() }));

    // Load inventory items for matching
    const invSnap = await db.collection(collections.inventory)
      .where('restaurantId', '==', restaurantId).get();
    const invItems = [];
    invSnap.forEach(doc => invItems.push({ id: doc.id, ...doc.data() }));

    const recipeContext = recipes.map(r =>
      `- ${r.name} (ID: ${r.id}, servings: ${r.servings || 1}): ingredients=[${(r.ingredients || []).map(i => `${i.inventoryItemName} ${i.quantity}${i.unit}`).join(', ')}]`
    ).join('\n');

    const inventoryContext = invItems.map(i =>
      `- ${i.name} (ID: ${i.id}, unit: ${i.unit}, cost: ₹${i.costPerUnit || 0}/${i.unit}, stock: ${i.currentStock}${i.unit})`
    ).join('\n');

    const completion = await openai.chat.completions.create({
      model: 'gpt-4o-mini',
      messages: [
        {
          role: 'system',
          content: `You are a restaurant waste analyst. The chef is telling you what leftover food they have at end-of-day.

Your job:
1. Parse the leftover items from their text (handle Hindi, casual language, approximate amounts)
2. For each leftover item, find the matching recipe from the restaurant's recipes
3. Calculate the ingredient breakdown: how much of each raw ingredient is in the leftover amount
4. If no recipe matches, estimate common ingredients for that dish

RESTAURANT RECIPES:
${recipeContext}

INVENTORY ITEMS:
${inventoryContext}

CALCULATION RULES:
- If recipe makes ${'{'}servings${'}'}  portions and leftover is X units, scale ingredients by (X / servings)
- For weight-based leftovers (kg/g), estimate how many servings that represents
- Match ingredient names to inventory items by name (fuzzy match OK)
- Include inventoryItemId if you can match to an inventory item
- Return costPerUnit from inventory data
- Handle unit conversions: 1kg=1000g, 1L=1000ml

Return JSON:
{
  "items": [
    {
      "name": "Paneer Butter Masala",
      "quantity": 1, "unit": "kg",
      "recipeId": "recipe_id_or_null",
      "recipeName": "matched recipe name or null",
      "estimatedServings": 4,
      "ingredients": [
        { "inventoryItemId": "id_or_null", "name": "Paneer", "qty": 400, "unit": "g", "costPerUnit": 0.4, "wasteValue": 160 }
      ],
      "totalWasteValue": 280
    }
  ]
}`
        },
        { role: 'user', content: text }
      ],
      temperature: 0.2,
      max_tokens: 2000,
      response_format: { type: 'json_object' }
    });

    let parsed;
    try {
      parsed = JSON.parse(completion.choices[0].message.content);
    } catch {
      return res.status(500).json({ error: 'AI response could not be parsed' });
    }

    res.json(parsed);
  } catch (error) {
    console.error('Analyze leftovers error:', error);
    res.status(500).json({ error: 'Failed to analyze leftovers' });
  }
});

// POST - Confirm leftover waste (after AI analysis, chef picks waste vs carry forward)
app.post('/api/inventory/:restaurantId/confirm-leftover-waste', authenticateToken, async (req, res) => {
  try {
    const { restaurantId } = req.params;
    const { userId } = req.user;
    const { items } = req.body;
    // items = [{ name, quantity, unit, ingredients: [{ inventoryItemId, name, qty, unit, costPerUnit, wasteValue }], totalWasteValue }]

    if (!items || !Array.isArray(items) || items.length === 0) {
      return res.status(400).json({ error: 'items array is required' });
    }

    const results = [];

    for (const item of items) {
      // For each leftover item marked as waste, deduct its ingredients from inventory
      for (const ing of (item.ingredients || [])) {
        if (!ing.inventoryItemId || !ing.qty || ing.qty <= 0) continue;

        const itemDoc = await db.collection(collections.inventory).doc(ing.inventoryItemId).get();
        if (!itemDoc.exists) continue;

        const invData = itemDoc.data();
        const oldStock = invData.currentStock || 0;
        const deductQty = ing.qty;

        // Unit conversion: if ingredient is in g but inventory is in kg, convert
        let finalDeduct = deductQty;
        const ingUnit = (ing.unit || '').toLowerCase();
        const invUnit = (invData.unit || '').toLowerCase();
        if ((ingUnit === 'g' && invUnit === 'kg') || (ingUnit === 'ml' && invUnit === 'l')) {
          finalDeduct = deductQty / 1000;
        } else if ((ingUnit === 'kg' && invUnit === 'g') || (ingUnit === 'l' && invUnit === 'ml')) {
          finalDeduct = deductQty * 1000;
        }

        const newStock = Math.max(0, oldStock - finalDeduct);

        // FIFO batch deduction
        let remaining = finalDeduct;
        const batchesSnap = await db.collection(collections.stockBatches)
          .where('restaurantId', '==', restaurantId)
          .where('inventoryItemId', '==', ing.inventoryItemId)
          .where('status', '==', 'active').get();
        const batches = [];
        batchesSnap.forEach(doc => {
          const d = doc.data();
          batches.push({ id: doc.id, ...d, expiryDate: d.expiryDate?.toDate?.() || d.expiryDate });
        });
        batches.sort((a, b) => {
          if (!a.expiryDate) return 1;
          if (!b.expiryDate) return -1;
          return new Date(a.expiryDate) - new Date(b.expiryDate);
        });
        for (const batch of batches) {
          if (remaining <= 0) break;
          const batchRem = batch.remainingQty || 0;
          if (batchRem <= 0) continue;
          const take = Math.min(remaining, batchRem);
          await db.collection(collections.stockBatches).doc(batch.id).update({
            remainingQty: batchRem - take,
            status: (batchRem - take) <= 0 ? 'depleted' : 'active',
            updatedAt: new Date()
          });
          remaining -= take;
        }

        await db.collection(collections.inventory).doc(ing.inventoryItemId).update({
          currentStock: newStock,
          wastedQty: (invData.wastedQty || 0) + finalDeduct,
          lastUpdated: new Date()
        });

        await db.collection(collections.inventoryTransactions).add({
          restaurantId, inventoryItemId: ing.inventoryItemId,
          inventoryItemName: ing.name || '',
          type: 'WASTE', source: 'LEFTOVER',
          quantityChange: -finalDeduct, previousStock: oldStock, newStock,
          unit: invData.unit || '', date: new Date(), performedBy: userId,
          notes: `EOD leftover: ${item.name} (${item.quantity} ${item.unit})`
        });

        // Create waste entry per ingredient
        await db.collection(collections.wasteEntries).add({
          restaurantId, itemId: ing.inventoryItemId,
          itemName: ing.name || '',
          quantity: finalDeduct, unit: invData.unit || '',
          reason: 'leftover', source: 'LEFTOVER',
          costPerUnit: ing.costPerUnit || invData.costPerUnit || 0,
          wasteValue: finalDeduct * (ing.costPerUnit || invData.costPerUnit || 0),
          notes: `From leftover: ${item.name} (${item.quantity} ${item.unit})`,
          batchId: null, recordedBy: userId, date: new Date(), createdAt: new Date()
        });

        results.push({ ingredient: ing.name, deducted: finalDeduct, unit: invData.unit, newStock });
      }
    }

    res.json({ success: true, deductions: results, itemsProcessed: items.length });
  } catch (error) {
    console.error('Confirm leftover waste error:', error);
    res.status(500).json({ error: 'Failed to confirm leftover waste' });
  }
});

// ══════════════════════════════════════════════════════════════
// SMART IMPORT — Parse text/image → create inventory + menu + recipes
// ══════════════════════════════════════════════════════════════
app.post('/api/inventory/:restaurantId/smart-import/parse', authenticateToken, aiUsageLimiter.middleware(), upload.single('image'), async (req, res) => {
  try {
    const { restaurantId } = req.params;
    const { text, mode } = req.body;
    const imageFile = req.file;
    const isInvoiceMode = mode === 'invoice' || (imageFile && !text);

    if (!text && !imageFile) {
      return res.status(400).json({ error: 'Either text or image is required' });
    }

    // Load existing inventory items and menu for duplicate detection
    const [inventorySnap, restaurantDoc] = await Promise.all([
      db.collection(collections.inventory).where('restaurantId', '==', restaurantId).get(),
      db.collection(collections.restaurants).doc(restaurantId).get()
    ]);

    if (!restaurantDoc.exists) {
      return res.status(404).json({ error: 'Restaurant not found' });
    }

    const restaurantData = restaurantDoc.data();
    const existingInventory = [];
    inventorySnap.forEach(doc => existingInventory.push({ id: doc.id, ...doc.data() }));

    // If restaurant has default seeded menu, treat it as empty (it will be cleared on confirm)
    const hasDefaultMenu = restaurantData.hasDefaultMenu;
    const existingMenuItems = hasDefaultMenu ? [] : (restaurantData.menu?.items || []).filter(i => i.status === 'active' || i.active === true);
    const existingCategories = hasDefaultMenu ? [] : (restaurantData.categories || []);

    let systemPrompt;
    let userMessage;

    if (isInvoiceMode) {
      // Invoice/purchase bill parsing mode
      const existingInvContext = existingInventory.length > 0
        ? `\nEXISTING INVENTORY ITEMS (set "isDuplicate": true if item matches):\n${existingInventory.map(i => `- ${i.name} (${i.unit}, category: ${i.category})`).join('\n')}`
        : '';

      systemPrompt = `You are analyzing a supplier invoice, purchase bill, or delivery receipt for a restaurant. Extract ALL line items from this document.

${existingInvContext}

Return a JSON object with this exact structure:
{
  "supplierInfo": {
    "name": "Supplier Company Name",
    "invoiceNumber": "INV-12345",
    "date": "2025-04-28",
    "total": 15000
  },
  "inventoryItems": [
    {
      "name": "Tomatoes",
      "unit": "kg",
      "category": "Vegetables",
      "quantity": 10,
      "costPerUnit": 40,
      "totalCost": 400,
      "isNew": true
    }
  ]
}

RULES:
1. Extract EVERY line item from the invoice/bill, no matter how small.
2. For each item: extract name, quantity purchased, unit (kg/g/L/ml/pcs/dozen/bottle/can/bag/box/pack), cost per unit, and total cost.
3. Categorize items: Vegetables, Fruits, Dairy, Meat & Poultry, Seafood, Spices & Masala, Beverages, Dry Goods & Grains, Oils & Ghee, Bakery, Cleaning & Supplies, Packaging, Other.
4. Extract supplier info from the invoice header/footer: supplier name, invoice number, date, total amount.
5. If an item already exists in EXISTING INVENTORY ITEMS, set "isDuplicate": true (case-insensitive match). Otherwise set "isNew": true.
6. Parse Hindi, regional, or abbreviated item names correctly (e.g., "Aalu" = "Potato", "Desi Ghee" = "Desi Ghee").
7. If cost per unit is not directly visible but total cost and quantity are, calculate it.
8. All monetary values should be in INR (₹).
9. Return valid JSON only — no markdown, no explanation.`;

      userMessage = imageFile
        ? 'Extract all items, quantities, costs, and supplier details from this invoice/bill image.'
        : `Extract all items, quantities, costs, and supplier details from this invoice text:\n\n${text}`;

    } else {
      // Original recipe/menu parsing mode
      const existingContext = `
EXISTING INVENTORY ITEMS (do NOT re-create these, reference them by name):
${existingInventory.map(i => `- ${i.name} (${i.unit}, category: ${i.category})`).join('\n') || 'None'}

EXISTING MENU ITEMS:
${existingMenuItems.map(i => `- ${i.name} (₹${i.price}, category: ${i.category})`).join('\n') || 'None'}

EXISTING MENU CATEGORIES:
${existingCategories.map(c => c.name).join(', ') || 'None'}`;

      systemPrompt = `You are a restaurant setup assistant. Parse the provided text (or image) which contains recipes, ingredient lists, or menu items. Extract structured data to set up the restaurant's inventory, menu, and recipes.

${existingContext}

Return a JSON object with these arrays:
{
  "inventoryItems": [
    { "name": "Tea Leaves", "unit": "g", "category": "Beverages", "costPerUnit": 0.5, "isNew": true }
  ],
  "menuCategories": ["Hot Beverages", "Cold Beverages"],
  "menuItems": [
    { "name": "Masala Tea", "price": 30, "category": "Hot Beverages", "description": "Traditional Indian spiced tea", "isVeg": true }
  ],
  "recipes": [
    {
      "menuItemName": "Masala Tea",
      "servings": 1,
      "category": "Beverages",
      "ingredients": [
        { "itemName": "Tea Leaves", "qty": 5, "unit": "g" },
        { "itemName": "Milk", "qty": 150, "unit": "ml" },
        { "itemName": "Sugar", "qty": 10, "unit": "g" }
      ],
      "instructions": "Boil water, add tea leaves and spices, add milk, strain and serve."
    }
  ]
}

RULES:
1. For inventoryItems: set "isNew": false if the item already exists in EXISTING INVENTORY ITEMS (match by name, case-insensitive). Set "isNew": true for new items only.
2. For menuCategories: only include NEW categories not already in EXISTING MENU CATEGORIES.
3. For menuItems: skip items that already exist in EXISTING MENU ITEMS (match by name).
4. For recipes: always create recipes linking menuItems to inventoryItems.
5. Use sensible units: g, kg, ml, L, pieces, nos, bunches, etc.
6. Estimate reasonable prices in INR (₹) for menu items if not provided.
7. Estimate reasonable cost per unit in INR for inventory items if not provided.
8. Parse Hindi/regional ingredient names correctly.
9. If the text has multiple recipes, extract ALL of them.
10. Return valid JSON only.`;

      userMessage = imageFile
        ? 'Extract all recipes, ingredients, and menu items from this image.'
        : text;
    }

    let aiResponse;

    if (imageFile) {
      const imageBase64 = imageFile.buffer.toString('base64');
      const imageMimeType = imageFile.mimetype;

      const completion = await openai.chat.completions.create({
        model: 'gpt-4o',
        messages: [
          { role: 'system', content: systemPrompt },
          {
            role: 'user',
            content: [
              { type: 'text', text: userMessage },
              { type: 'image_url', image_url: { url: `data:${imageMimeType};base64,${imageBase64}` } }
            ]
          }
        ],
        temperature: 0.2,
        max_tokens: 4000,
      });
      aiResponse = completion.choices[0].message.content.trim();
    } else {
      const completion = await openai.chat.completions.create({
        model: 'gpt-4o-mini',
        messages: [
          { role: 'system', content: systemPrompt },
          { role: 'user', content: userMessage }
        ],
        temperature: 0.2,
        max_tokens: 4000,
        response_format: { type: 'json_object' },
      });
      aiResponse = completion.choices[0].message.content.trim();
    }

    // Parse AI response
    let parsed;
    try {
      const jsonMatch = aiResponse.match(/```json\s*([\s\S]*?)\s*```/) || aiResponse.match(/```\s*([\s\S]*?)\s*```/);
      parsed = jsonMatch ? JSON.parse(jsonMatch[1]) : JSON.parse(aiResponse);
    } catch (parseError) {
      console.error('Smart import parse error:', aiResponse);
      return res.status(500).json({ error: 'AI could not parse the input. Try rephrasing or simplifying.' });
    }

    // Validate and enrich
    const result = {
      inventoryItems: (parsed.inventoryItems || []).map(item => ({
        name: (item.name || '').trim(),
        unit: (item.unit || 'g').trim(),
        category: (item.category || 'General').trim(),
        costPerUnit: parseFloat(item.costPerUnit) || 0,
        quantity: parseFloat(item.quantity) || 0,
        totalCost: parseFloat(item.totalCost) || 0,
        isNew: item.isNew !== false,
        isDuplicate: existingInventory.some(e => e.name.toLowerCase() === (item.name || '').toLowerCase().trim()),
        existingId: existingInventory.find(e => e.name.toLowerCase() === (item.name || '').toLowerCase().trim())?.id || null,
      })),
      menuCategories: (parsed.menuCategories || []).filter(c => c && typeof c === 'string').map(c => c.trim()),
      menuItems: (parsed.menuItems || []).map(item => ({
        name: (item.name || '').trim(),
        price: parseFloat(item.price) || 0,
        category: (item.category || 'Other').trim(),
        description: (item.description || '').trim(),
        isVeg: item.isVeg !== false,
        isDuplicate: existingMenuItems.some(e => e.name.toLowerCase() === (item.name || '').toLowerCase().trim()),
      })),
      recipes: (parsed.recipes || []).map(recipe => ({
        menuItemName: (recipe.menuItemName || '').trim(),
        servings: parseInt(recipe.servings) || 1,
        category: (recipe.category || 'Main Course').trim(),
        ingredients: (recipe.ingredients || []).map(ing => ({
          itemName: (ing.itemName || '').trim(),
          qty: parseFloat(ing.qty) || 0,
          unit: (ing.unit || 'g').trim(),
        })),
        instructions: (recipe.instructions || '').trim(),
      })),
    };

    // Include supplier info for invoice mode
    if (isInvoiceMode && parsed.supplierInfo) {
      result.supplierInfo = {
        name: (parsed.supplierInfo.name || '').trim(),
        invoiceNumber: (parsed.supplierInfo.invoiceNumber || '').trim(),
        date: (parsed.supplierInfo.date || '').trim(),
        total: parseFloat(parsed.supplierInfo.total) || 0,
      };
    }

    console.log(`🧠 Smart import parsed (${isInvoiceMode ? 'invoice' : 'text'}): ${result.inventoryItems.length} inventory, ${result.menuItems.length} menu, ${result.recipes.length} recipes`);

    res.json({ success: true, data: result });

  } catch (error) {
    console.error('Smart import parse error:', error);
    res.status(500).json({ error: 'Failed to parse input', message: error.message });
  }
});

app.post('/api/inventory/:restaurantId/smart-import/confirm', authenticateToken, async (req, res) => {
  try {
    const { restaurantId } = req.params;
    const { userId, role } = req.user;
    const { inventoryItems = [], menuCategories = [], menuItems = [], recipes = [], supplierInfo } = req.body;

    if (!inventoryItems.length && !menuItems.length && !recipes.length) {
      return res.status(400).json({ error: 'Nothing to import' });
    }

    const summary = { inventoryItems: 0, menuCategories: 0, menuItems: 0, recipes: 0 };
    const errors = [];

    // 1. Create inventory items (skip duplicates)
    const inventoryMap = {}; // name → id mapping for recipe linking

    // First, load existing inventory for mapping
    const existingInvSnap = await db.collection(collections.inventory)
      .where('restaurantId', '==', restaurantId).get();
    existingInvSnap.forEach(doc => {
      inventoryMap[doc.data().name.toLowerCase()] = doc.id;
    });

    for (const item of inventoryItems) {
      if (item.isDuplicate || !item.isNew) {
        // Use existing item's ID
        if (item.existingId) inventoryMap[item.name.toLowerCase()] = item.existingId;
        // If invoice mode and item has quantity, update existing item's stock
        const addQty = parseFloat(item.quantity) || 0;
        if (addQty > 0 && item.existingId) {
          try {
            const existDoc = await db.collection(collections.inventory).doc(item.existingId).get();
            if (existDoc.exists) {
              const existData = existDoc.data();
              const oldStock = existData.currentStock || 0;
              const newStock = oldStock + addQty;
              const newCostPerUnit = parseFloat(item.costPerUnit) || existData.costPerUnit || 0;
              const prevCostPerUnit = existData.costPerUnit || 0;
              await db.collection(collections.inventory).doc(item.existingId).update({
                currentStock: newStock,
                costPerUnit: newCostPerUnit,
                supplier: supplierInfo?.name || existData.supplier || '',
                updatedAt: new Date(),
                updatedBy: userId,
              });
              // Create stock batch for FIFO tracking
              await db.collection(collections.stockBatches).add({
                restaurantId,
                inventoryItemId: item.existingId,
                inventoryItemName: existData.name,
                quantity: addQty,
                remainingQty: addQty,
                unit: existData.unit || item.unit || '',
                costPerUnit: newCostPerUnit,
                supplier: supplierInfo?.name || '',
                addedBy: userId,
                source: 'smart-import',
                status: 'active',
                createdAt: new Date(),
                updatedAt: new Date()
              });
              // Log transaction with price info
              await db.collection(collections.inventoryTransactions).add({
                restaurantId,
                inventoryItemId: item.existingId,
                inventoryItemName: existData.name,
                type: 'ADDITION',
                source: 'SMART_IMPORT',
                quantityChange: addQty,
                previousStock: oldStock,
                newStock: newStock,
                unit: existData.unit || item.unit || '',
                costPerUnit: newCostPerUnit,
                previousCostPerUnit: prevCostPerUnit,
                totalCost: addQty * newCostPerUnit,
                date: new Date(),
                performedBy: userId,
                notes: supplierInfo?.name ? `Smart import from ${supplierInfo.name}` : 'Smart import stock addition'
              });
              summary.inventoryItems++;
            }
          } catch (e) {
            errors.push(`Failed to update stock for ${item.name}: ${e.message}`);
          }
        }
        continue;
      }
      try {
        // Check if already exists (safety check)
        if (inventoryMap[item.name.toLowerCase()]) continue;

        const importedQty = parseFloat(item.quantity) || 0;
        const itemData = {
          restaurantId,
          name: item.name.trim(),
          category: item.category.trim(),
          unit: item.unit.trim(),
          currentStock: importedQty,
          minStock: 0,
          maxStock: 0,
          costPerUnit: parseFloat(item.costPerUnit) || 0,
          supplier: supplierInfo?.name || '',
          description: '',
          barcode: '',
          expiryDate: null,
          mfgDate: null,
          expiryDays: null,
          location: '',
          status: 'good',
          createdAt: new Date(),
          updatedAt: new Date(),
          createdBy: userId,
          updatedBy: userId
        };

        const ref = await db.collection(collections.inventory).add(itemData);
        inventoryMap[item.name.toLowerCase()] = ref.id;

        // Create initial stock batch if quantity > 0
        if (importedQty > 0) {
          await db.collection(collections.stockBatches).add({
            restaurantId,
            inventoryItemId: ref.id,
            inventoryItemName: item.name.trim(),
            quantity: importedQty,
            remainingQty: importedQty,
            unit: item.unit.trim(),
            costPerUnit: parseFloat(item.costPerUnit) || 0,
            supplier: supplierInfo?.name || '',
            addedBy: userId,
            source: 'smart-import',
            status: 'active',
            createdAt: new Date(),
            updatedAt: new Date()
          });
          // Log initial stock transaction
          await db.collection(collections.inventoryTransactions).add({
            restaurantId,
            inventoryItemId: ref.id,
            inventoryItemName: item.name.trim(),
            type: 'ADDITION',
            source: 'SMART_IMPORT',
            quantityChange: importedQty,
            previousStock: 0,
            newStock: importedQty,
            unit: item.unit.trim(),
            costPerUnit: parseFloat(item.costPerUnit) || 0,
            previousCostPerUnit: 0,
            totalCost: importedQty * (parseFloat(item.costPerUnit) || 0),
            date: new Date(),
            performedBy: userId,
            notes: supplierInfo?.name ? `Smart import from ${supplierInfo.name}` : 'Initial stock from smart import'
          });
        }

        summary.inventoryItems++;
      } catch (e) {
        errors.push(`Inventory "${item.name}": ${e.message}`);
      }
    }

    // 2. Add menu categories
    const restaurantDoc = await db.collection(collections.restaurants).doc(restaurantId).get();
    if (!restaurantDoc.exists) {
      return res.status(404).json({ error: 'Restaurant not found' });
    }
    const restaurantData = restaurantDoc.data();
    const existingMenu = restaurantData.menu || { items: [] };

    // If restaurant has default seeded menu, clear it before adding real items
    let existingCats;
    let existingMenuItemsList;
    if (restaurantData.hasDefaultMenu) {
      existingCats = [];
      existingMenuItemsList = [];
      console.log('🔄 Smart Import: Clearing default seeded menu before import');
    } else {
      existingCats = [...(restaurantData.categories || [])];
      existingMenuItemsList = [...(existingMenu.items || [])];
    }

    for (const catName of menuCategories) {
      const id = categoryNameToId(catName);
      if (!id || existingCats.some(c => (c.id || '').toLowerCase() === id)) continue;
      existingCats.push({ id, name: catName.trim(), emoji: '🍽️', description: '' });
      summary.menuCategories++;
    }

    // 3. Add menu items
    let maxShortCode = 0;
    for (const item of existingMenuItemsList) {
      const sc = parseInt(item.shortCode, 10);
      if (!isNaN(sc) && sc > maxShortCode) maxShortCode = sc;
    }

    const menuItemNameToId = {};
    // Map existing menu items
    for (const item of existingMenuItemsList) {
      menuItemNameToId[item.name.toLowerCase()] = item.id;
    }

    for (const item of menuItems) {
      if (item.isDuplicate) continue;
      if (menuItemNameToId[item.name.toLowerCase()]) continue;

      try {
        const rawCat = item.category || 'Other';
        const resolvedId = categoryNameToId(rawCat);
        const validCatIds = new Set(existingCats.map(c => (c.id || '').toLowerCase()));
        const categoryId = (resolvedId && validCatIds.has(resolvedId)) ? resolvedId : 'other';

        // Ensure 'other' category exists
        if (categoryId === 'other' && !existingCats.some(c => c.id === 'other')) {
          existingCats.push({ id: 'other', name: 'Other', emoji: '🍽️', description: '' });
        }

        maxShortCode++;
        const menuItem = {
          id: `item_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`,
          restaurantId,
          name: item.name.trim(),
          description: item.description || '',
          price: parseFloat(item.price) || 0,
          category: categoryId,
          isVeg: item.isVeg !== false,
          spiceLevel: 'medium',
          allergens: [],
          shortCode: String(maxShortCode),
          status: 'active',
          order: existingMenuItemsList.length,
          isAvailable: true,
          stockQuantity: null,
          lowStockThreshold: 5,
          isStockManaged: false,
          variants: [],
          customizations: [],
          pricingRules: {},
          createdAt: new Date(),
          updatedAt: new Date(),
          source: 'smart_import'
        };

        existingMenuItemsList.push(menuItem);
        menuItemNameToId[item.name.toLowerCase()] = menuItem.id;
        summary.menuItems++;
      } catch (e) {
        errors.push(`Menu "${item.name}": ${e.message}`);
      }
    }

    // Save menu + categories update
    if (summary.menuCategories > 0 || summary.menuItems > 0 || restaurantData.hasDefaultMenu) {
      const updateData = {
        categories: existingCats,
        menu: { ...existingMenu, items: existingMenuItemsList, lastUpdated: new Date() },
        updatedAt: new Date()
      };
      // Clear hasDefaultMenu flag when replacing default menu with real items
      if (restaurantData.hasDefaultMenu) {
        updateData.hasDefaultMenu = false;
      }
      await db.collection(collections.restaurants).doc(restaurantId).update(updateData);
      invalidateRestaurantCache(restaurantId);
    }

    // 4. Create recipes
    for (const recipe of recipes) {
      try {
        const ingredients = recipe.ingredients.map(ing => {
          const invId = inventoryMap[ing.itemName.toLowerCase()] || null;
          return {
            inventoryItemId: invId,
            inventoryItemName: ing.itemName,
            quantity: parseFloat(ing.qty) || 0,
            unit: ing.unit || 'g'
          };
        });

        const recipeData = {
          restaurantId,
          name: recipe.menuItemName.trim(),
          description: '',
          ingredients,
          instructions: recipe.instructions || '',
          servings: parseInt(recipe.servings) || 1,
          prepTime: 0,
          cookTime: 0,
          category: recipe.category || 'Main Course',
          isActive: true,
          createdAt: new Date(),
          updatedAt: new Date(),
          createdBy: userId
        };

        await db.collection(collections.recipes).add(recipeData);
        summary.recipes++;
      } catch (e) {
        errors.push(`Recipe "${recipe.menuItemName}": ${e.message}`);
      }
    }

    console.log(`✅ Smart import complete: ${JSON.stringify(summary)}`);

    res.json({
      success: true,
      message: `Import complete! Created ${summary.inventoryItems} inventory items, ${summary.menuCategories} categories, ${summary.menuItems} menu items, ${summary.recipes} recipes.`,
      summary,
      errors
    });

  } catch (error) {
    console.error('Smart import confirm error:', error);
    res.status(500).json({ error: 'Failed to import', message: error.message });
  }
});

