// Bulk delete customers
app.post('/api/customers/bulk-delete', authenticateToken, async (req, res) => {
  try {
    if (!(await checkFeaturePermission(req, 'customers', 'delete'))) {
      return res.status(403).json({ error: 'Access denied. Customers delete permission required.' });
    }
    const { userId } = req.user;
    const { customerIds, reason } = req.body;

    if (!Array.isArray(customerIds) || customerIds.length === 0) {
      return res.status(400).json({ error: 'customerIds array is required' });
    }
    if (customerIds.length > 200) {
      return res.status(400).json({ error: 'Maximum 200 customers can be deleted at once' });
    }

    // Verify user role and resolve restaurantId
    const userDoc = await db.collection(collections.users).doc(userId).get();
    const userData = userDoc.data();

    // Check role — only owner/admin can bulk delete
    if (!['owner', 'admin'].includes(userData.role)) {
      return res.status(403).json({ error: 'Only admin or owner can bulk delete customers.' });
    }

    // Resolve restaurantId: staff have it on user doc, owners need to derive from first customer
    let restaurantId = userData.restaurantId;
    if (!restaurantId) {
      const firstCustDoc = await db.collection(collections.customers).doc(customerIds[0]).get();
      if (!firstCustDoc.exists) return res.status(404).json({ error: 'Customer not found' });
      restaurantId = firstCustDoc.data().restaurantId;
      // Verify owner owns this restaurant
      const restDoc = await db.collection(collections.restaurants).doc(restaurantId).get();
      if (!restDoc.exists || restDoc.data().ownerId !== userId) {
        return res.status(403).json({ error: 'Access denied' });
      }
    }

    // Delete in batches of 10
    let deletedCount = 0;
    const batchSize = 10;
    for (let i = 0; i < customerIds.length; i += batchSize) {
      const batch = db.batch();
      const chunk = customerIds.slice(i, i + batchSize);
      for (const custId of chunk) {
        const custRef = db.collection(collections.customers).doc(custId);
        const custDoc = await custRef.get();
        if (custDoc.exists && custDoc.data().restaurantId === restaurantId) {
          batch.delete(custRef);
          deletedCount++;
        }
      }
      await batch.commit();
    }

    // Also remove deleted customer IDs from any customer groups
    const groupsSnap = await db.collection('customerGroups').where('restaurantId', '==', restaurantId).get();
    if (!groupsSnap.empty) {
      for (const groupDoc of groupsSnap.docs) {
        const gData = groupDoc.data();
        const existingIds = gData.customerIds || [];
        const filtered = existingIds.filter(id => !customerIds.includes(id));
        if (filtered.length !== existingIds.length) {
          await groupDoc.ref.update({ customerIds: filtered, customerCount: filtered.length, updatedAt: new Date() });
        }
      }
    }

    console.log(`🗑️ Bulk deleted ${deletedCount} customers for restaurant ${restaurantId}. Reason: ${reason || 'not specified'}`);
    res.json({ message: `${deletedCount} customers deleted successfully`, deletedCount });
  } catch (error) {
    console.error('Bulk delete customers error:', error);
    res.status(500).json({ error: 'Failed to bulk delete customers' });
  }
});

// Helper function to get next open time
function getNextOpenTime(operatingHours, currentTime) {
  const days = ['sunday', 'monday', 'tuesday', 'wednesday', 'thursday', 'friday', 'saturday'];
  const currentDayIndex = currentTime.getDay();
  
  for (let i = 1; i <= 7; i++) {
    const nextDayIndex = (currentDayIndex + i) % 7;
    const nextDay = days[nextDayIndex];
    const nextDayHours = operatingHours[nextDay];
    
    if (nextDayHours && nextDayHours.isOpen) {
      return {
        day: nextDay,
        time: nextDayHours.open
      };
    }
  }
  
  return null;
}

// ==================== OFFERS MANAGEMENT APIs ====================

// Get all offers for a restaurant
app.get('/api/offers/:restaurantId', authenticateToken, async (req, res) => {
  try {
    const { restaurantId } = req.params;
    const { userId } = req.user;

    // Verify user has access to this restaurant
    const restaurant = await db.collection(collections.restaurants).doc(restaurantId).get();
    if (!restaurant.exists || restaurant.data().ownerId !== userId) {
      return res.status(403).json({ error: 'Access denied' });
    }

    const offersSnapshot = await db.collection('offers')
      .where('restaurantId', '==', restaurantId)
      .orderBy('createdAt', 'desc')
      .get();

    const offers = [];
    offersSnapshot.forEach(doc => {
      offers.push({
        id: doc.id,
        ...doc.data()
      });
    });

    // Optional eligibility enrichment when customerId/phone passed
    try {
      const { customerId, phone } = req.query || {};
      if (customerId || phone) {
        let customerGroupIds = [];
        try {
          const groupsSnap = await db.collection('customerGroups')
            .where('restaurantId', '==', restaurantId)
            .get();
          groupsSnap.forEach(doc => {
            const data = doc.data() || {};
            const members = data.customerIds || data.members || [];
            const memberPhones = (data.customerPhones || []).map(offerEngine.normalizePhone).filter(Boolean);
            const normPhone = offerEngine.normalizePhone(phone);
            if ((customerId && members.includes(customerId)) || (normPhone && memberPhones.includes(normPhone))) {
              customerGroupIds.push(doc.id);
            }
          });
        } catch (e) {
          // Best-effort only
        }
        const context = { customerId, customerPhone: phone, customerGroupIds, isFirstOrder: false };
        offers.forEach(o => {
          const audienceOk = offerEngine.matchesAudience(o, context);
          o._eligible = audienceOk;
          if (!audienceOk) {
            const t = (o.audience && o.audience.type) || (o.isFirstOrderOnly ? 'first_order' : 'all');
            o._eligibilityReason = t === 'first_order' ? 'First-order customers only'
              : t === 'groups' ? 'Not in a qualifying customer group'
              : t === 'customers' ? 'Not on the eligible customer list'
              : 'Not eligible';
          }
        });
      }
    } catch (enrichErr) {
      console.error('[offerEngine] eligibility enrichment failed:', enrichErr);
    }

    res.json({ offers });
  } catch (error) {
    console.error('Get offers error:', error);
    res.status(500).json({ error: 'Failed to fetch offers' });
  }
});

// Preview applicable offers and best offer for a given cart/customer (Phase 2)
app.post('/api/offers/preview', authenticateToken, async (req, res) => {
  try {
    const { restaurantId, cart = [], subtotal = 0, customerId, customerPhone, isFirstOrder } = req.body || {};
    if (!restaurantId) {
      return res.status(400).json({ success: false, error: 'restaurantId required' });
    }

    // Load active offers for restaurant
    const snap = await db.collection('offers')
      .where('restaurantId', '==', restaurantId)
      .where('isActive', '==', true)
      .get();
    const offers = [];
    snap.forEach(doc => offers.push({ id: doc.id, ...doc.data() }));

    // Build customer context: fetch customer groups
    let customerGroupIds = [];
    if (customerId || customerPhone) {
      try {
        const groupsSnap = await db.collection('customerGroups')
          .where('restaurantId', '==', restaurantId)
          .get();
        const normPhone = offerEngine.normalizePhone(customerPhone);
        groupsSnap.forEach(doc => {
          const data = doc.data() || {};
          const members = data.customerIds || data.members || [];
          const memberPhones = (data.customerPhones || []).map(offerEngine.normalizePhone).filter(Boolean);
          if ((customerId && members.includes(customerId)) || (normPhone && memberPhones.includes(normPhone))) {
            customerGroupIds.push(doc.id);
          }
        });
      } catch (e) {
        console.error('[offerEngine] preview: customerGroups lookup failed', e);
      }
    }

    const context = { customerId, customerPhone, customerGroupIds, isFirstOrder: !!isFirstOrder };
    const now = new Date();

    let applicable = offerEngine.filterApplicableOffers(offers, { subtotal, cart, context, now });

    // Per-customer usage enforcement
    const customerKey = offerEngine.buildCustomerKey(customerId, customerPhone);
    if (customerKey) {
      const offerIdsToCheck = applicable.filter(o => o.usageLimitPerCustomer).map(o => o.id);
      if (offerIdsToCheck.length > 0) {
        const usageMap = await offerEngine.getCustomerUsageMap(db, offerIdsToCheck, customerKey);
        applicable = applicable.filter(o => {
          if (!o.usageLimitPerCustomer) return true;
          return (usageMap[o.id] || 0) < Number(o.usageLimitPerCustomer);
        });
      }
    }

    const applicableResults = applicable.map(offer => {
      const result = offerEngine.calculateDiscountForOffer(offer, subtotal, cart, context);
      return {
        offer,
        discount: result.discount,
        freeItems: result.freeItems,
        appliedTier: result.appliedTier,
      };
    });

    const bestOffer = offerEngine.pickBestOffer(applicable, subtotal, cart, context);
    let best = null;
    if (bestOffer) {
      const r = offerEngine.calculateDiscountForOffer(bestOffer, subtotal, cart, context);
      best = { offerId: bestOffer.id, discount: r.discount };
    }

    res.json({ success: true, applicable: applicableResults, best });
  } catch (error) {
    console.error('[offerEngine] preview error:', error);
    res.status(500).json({ success: false, error: 'Failed to preview offers' });
  }
});

// Get customer loyalty data by phone (public endpoint for Crave app)
app.post('/api/public/customer/lookup', vercelSecurityMiddleware.publicAPI, async (req, res) => {
  try {
    const { restaurantId, phone, countryCode } = req.body;

    if (!restaurantId || !phone) {
      return res.status(400).json({ error: 'Restaurant ID and phone are required' });
    }

    // Country dial code map
    const countryDialCodes = {
      'IN': '91', 'US': '1', 'CA': '1', 'GB': '44', 'AU': '61', 'AE': '971',
      'SG': '65', 'MY': '60', 'TH': '66', 'PH': '63', 'ID': '62', 'NZ': '64',
      'ZA': '27', 'KE': '254', 'NG': '234', 'DE': '49', 'FR': '33', 'IT': '39',
      'ES': '34', 'NL': '31', 'BE': '32', 'SE': '46', 'NO': '47', 'DK': '45',
      'JP': '81', 'KR': '82', 'CN': '86', 'HK': '852', 'TW': '886',
      'BR': '55', 'MX': '52', 'AR': '54', 'CL': '56', 'CO': '57',
      'SA': '966', 'QA': '974', 'KW': '965', 'BH': '973', 'OM': '968',
      'LK': '94', 'NP': '977', 'BD': '880', 'PK': '92', 'MM': '95'
    };
    const dialCode = countryDialCodes[countryCode] || '91'; // Default to India
    const localPhoneLength = ['US', 'CA', 'IN', 'GB', 'AU', 'FR', 'DE'].includes(countryCode) ? 10 : 
                             ['SG', 'HK'].includes(countryCode) ? 8 : 
                             ['MY', 'PH', 'ID', 'TH', 'KR', 'JP'].includes(countryCode) ? 9 : 10;

    // Helper function to normalize phone number (country-aware)
    const normalizePhone = (phoneNum) => {
      if (phoneNum === null || phoneNum === undefined || phoneNum === '') return null;
      const digits = String(phoneNum).replace(/\D/g, '');
      // Strip country dial code if present
      if (digits.startsWith(dialCode) && digits.length === dialCode.length + localPhoneLength) {
        return digits.substring(dialCode.length);
      }
      // Handle 0-prefix (common in many countries)
      if (digits.startsWith('0') && digits.length === localPhoneLength + 1) {
        return digits.substring(1);
      }
      if (digits.length === localPhoneLength) {
        return digits;
      }
      return digits;
    };

    const normalizedPhone = normalizePhone(phone);

    // Try exact match first
    let customerQuery = await db.collection('customers')
      .where('restaurantId', '==', restaurantId)
      .where('phone', '==', phone)
      .limit(1)
      .get();

    let existingCustomer = null;
    if (!customerQuery.empty) {
      existingCustomer = customerQuery.docs[0];
    } else if (normalizedPhone) {
      // Try normalized phone match
      const allCustomers = await db.collection('customers')
        .where('restaurantId', '==', restaurantId)
        .get();

      existingCustomer = allCustomers.docs.find(doc => {
        const custPhone = normalizePhone(doc.data().phone);
        return custPhone === normalizedPhone;
      });
    }

    if (existingCustomer) {
      const customerData = existingCustomer.data();
      const totalOrders = customerData.totalOrders || 0;
      res.json({
        found: true,
        customer: {
          id: existingCustomer.id,
          name: customerData.name || 'Customer',
          phone: customerData.phone || normalizedPhone || phone,
          loyaltyPoints: customerData.loyaltyPoints || 0,
          totalOrders: totalOrders,
          totalSpent: customerData.totalSpent || 0,
          // First order if customer exists but has never placed an order
          isFirstOrder: totalOrders === 0
        }
      });
    } else {
      res.json({
        found: false,
        customer: {
          loyaltyPoints: 0,
          totalOrders: 0,
          isFirstOrder: true
        }
      });
    }
  } catch (error) {
    console.error('Customer lookup error:', error);
    res.status(500).json({ error: 'Failed to lookup customer' });
  }
});

// Firebase auth verification for Crave customer app
// Verifies Firebase ID token and creates/links customer with tier-based loyalty
app.post('/api/crave-app/auth/firebase/verify', vercelSecurityMiddleware.publicAPI, async (req, res) => {
  try {
    const { firebaseIdToken, restaurantId, name } = req.body;

    if (!firebaseIdToken || !restaurantId) {
      return res.status(400).json({ error: 'Firebase ID token and restaurant ID are required' });
    }

    // Verify Firebase ID token
    const admin = require('firebase-admin');
    let decodedToken;
    try {
      decodedToken = await admin.auth().verifyIdToken(firebaseIdToken);
    } catch (error) {
      console.error('Firebase token verification error:', error);
      return res.status(401).json({ error: 'Invalid or expired Firebase token' });
    }

    const { uid, phone_number: phoneNumber } = decodedToken;
    console.log('🔐 Crave app Firebase auth - UID:', uid, 'Phone:', phoneNumber);

    // Normalize phone number
    const normalizePhone = (phoneNum) => {
      if (phoneNum === null || phoneNum === undefined || phoneNum === '') return null;
      const digits = String(phoneNum).replace(/\D/g, '');
      if (digits.length === 12 && digits.startsWith('91')) {
        return digits.substring(2);
      } else if (digits.length === 10) {
        return digits;
      } else if (digits.length === 11 && digits.startsWith('0')) {
        return digits.substring(1);
      }
      return digits;
    };

    const normalizedPhone = normalizePhone(phoneNumber);

    // Try to find existing customer by Firebase UID first
    let customerDoc = null;
    let existingCustomerQuery = await db.collection('customers')
      .where('restaurantId', '==', restaurantId)
      .where('firebaseUid', '==', uid)
      .limit(1)
      .get();

    if (!existingCustomerQuery.empty) {
      customerDoc = existingCustomerQuery.docs[0];
      console.log('✅ Customer found by Firebase UID:', customerDoc.id);
    } else if (normalizedPhone) {
      // Try to find by phone number
      const phoneQuery = await db.collection('customers')
        .where('restaurantId', '==', restaurantId)
        .where('phone', '==', normalizedPhone)
        .limit(1)
        .get();

      if (!phoneQuery.empty) {
        customerDoc = phoneQuery.docs[0];
        // Link Firebase UID to existing customer
        await db.collection('customers').doc(customerDoc.id).update({
          firebaseUid: uid,
          updatedAt: new Date()
        });
        console.log('✅ Customer found by phone, linked Firebase UID:', customerDoc.id);
      }
    }

    // Tier calculation function
    const calculateTier = (lifetimePoints) => {
      if (lifetimePoints >= 5000) return 'platinum';
      if (lifetimePoints >= 2000) return 'gold';
      if (lifetimePoints >= 500) return 'silver';
      return 'bronze';
    };

    let customer;
    let isNewCustomer = false;

    if (customerDoc) {
      // Existing customer - update if name provided
      const customerData = customerDoc.data();
      const lifetimePoints = customerData.lifetimePoints || customerData.loyaltyPoints || 0;
      const loyaltyTier = calculateTier(lifetimePoints);

      if (name && (!customerData.name || customerData.name === 'Customer')) {
        await db.collection('customers').doc(customerDoc.id).update({
          name: name,
          loyaltyTier: loyaltyTier,
          updatedAt: new Date()
        });
      } else if (customerData.loyaltyTier !== loyaltyTier) {
        // Update tier if changed
        await db.collection('customers').doc(customerDoc.id).update({
          loyaltyTier: loyaltyTier,
          updatedAt: new Date()
        });
      }

      customer = {
        id: customerDoc.id,
        name: name || customerData.name || 'Customer',
        phone: normalizedPhone || customerData.phone,
        loyaltyPoints: customerData.loyaltyPoints || 0,
        lifetimePoints: lifetimePoints,
        loyaltyTier: loyaltyTier,
        totalOrders: customerData.totalOrders || 0,
        totalSpent: customerData.totalSpent || 0
      };
    } else {
      // Create new customer
      isNewCustomer = true;
      const newCustomer = {
        restaurantId: restaurantId,
        firebaseUid: uid,
        phone: normalizedPhone,
        name: name || 'Customer',
        customerId: `CUST-${Date.now()}-${Math.random().toString(36).substr(2, 6)}`,
        loyaltyPoints: 0,
        lifetimePoints: 0,
        loyaltyTier: 'bronze',
        totalOrders: 0,
        totalSpent: 0,
        lastOrderDate: null,
        orderHistory: [],
        loyaltyTransactions: [],
        source: 'crave_app_firebase',
        createdAt: new Date(),
        updatedAt: new Date()
      };

      const customerRef = await db.collection('customers').add(newCustomer);
      console.log('✅ New Crave customer created:', customerRef.id);

      customer = {
        id: customerRef.id,
        name: newCustomer.name,
        phone: newCustomer.phone,
        loyaltyPoints: 0,
        lifetimePoints: 0,
        loyaltyTier: 'bronze',
        totalOrders: 0,
        totalSpent: 0
      };
    }

    // Generate JWT token for customer
    const token = jwt.sign(
      {
        customerId: customer.id,
        restaurantId: restaurantId,
        phone: customer.phone,
        type: 'customer'
      },
      process.env.JWT_SECRET,
      { expiresIn: '30d' }
    );

    res.json({
      token: token,
      customer: customer,
      isNewCustomer: isNewCustomer
    });

  } catch (error) {
    console.error('Crave Firebase auth error:', error);
    res.status(500).json({ error: 'Authentication failed' });
  }
});

// Get customer loyalty history with tier info (public endpoint for Crave app)
app.get('/api/public/customer/:customerId/loyalty-history', vercelSecurityMiddleware.publicAPI, async (req, res) => {
  try {
    const { customerId } = req.params;
    const { page = 1, limit = 20, type = 'all' } = req.query;

    const customerDoc = await db.collection('customers').doc(customerId).get();
    if (!customerDoc.exists) {
      return res.status(404).json({ error: 'Customer not found' });
    }

    const customerData = customerDoc.data();
    const loyaltyTransactions = customerData.loyaltyTransactions || [];
    const orderHistory = customerData.orderHistory || [];

    // Build transaction history from order history if loyaltyTransactions is empty
    let history = loyaltyTransactions.length > 0 ? loyaltyTransactions : [];

    if (history.length === 0 && orderHistory.length > 0) {
      // Build from order history
      orderHistory.forEach(order => {
        if (order.loyaltyPointsEarned > 0) {
          history.push({
            id: `earned-${order.orderId}`,
            type: 'earned',
            points: order.loyaltyPointsEarned,
            orderId: order.orderId,
            orderNumber: order.orderNumber,
            date: order.orderDate,
            description: `Earned from order #${order.orderNumber || order.orderId?.slice(-6)}`,
            tierAtTime: order.tierAtTime || 'bronze',
            tierMultiplier: order.tierMultiplier || 1
          });
        }
        if (order.loyaltyPointsRedeemed > 0) {
          history.push({
            id: `redeemed-${order.orderId}`,
            type: 'redeemed',
            points: order.loyaltyPointsRedeemed,
            orderId: order.orderId,
            orderNumber: order.orderNumber,
            date: order.orderDate,
            description: `Redeemed on order #${order.orderNumber || order.orderId?.slice(-6)}`,
            tierAtTime: order.tierAtTime || 'bronze'
          });
        }
      });
    }

    // Filter by type
    if (type !== 'all') {
      history = history.filter(t => t.type === type);
    }

    // Sort by date descending
    history.sort((a, b) => {
      const dateA = a.date ? new Date(a.date) : new Date(0);
      const dateB = b.date ? new Date(b.date) : new Date(0);
      return dateB - dateA;
    });

    // Pagination
    const startIndex = (parseInt(page) - 1) * parseInt(limit);
    const paginatedHistory = history.slice(startIndex, startIndex + parseInt(limit));

    // Calculate summary
    const totalEarned = history
      .filter(t => t.type === 'earned')
      .reduce((sum, t) => sum + (t.points || 0), 0);
    const totalRedeemed = history
      .filter(t => t.type === 'redeemed')
      .reduce((sum, t) => sum + (t.points || 0), 0);

    // Tier calculation
    const lifetimePoints = customerData.lifetimePoints || totalEarned;
    const currentTier = customerData.loyaltyTier || (() => {
      if (lifetimePoints >= 5000) return 'platinum';
      if (lifetimePoints >= 2000) return 'gold';
      if (lifetimePoints >= 500) return 'silver';
      return 'bronze';
    })();

    // Points to next tier
    const tierThresholds = { bronze: 0, silver: 500, gold: 2000, platinum: 5000 };
    const tiers = ['bronze', 'silver', 'gold', 'platinum'];
    const currentTierIndex = tiers.indexOf(currentTier);
    const nextTier = currentTierIndex < 3 ? tiers[currentTierIndex + 1] : null;
    const pointsToNextTier = nextTier ? tierThresholds[nextTier] - lifetimePoints : 0;

    res.json({
      history: paginatedHistory,
      summary: {
        totalEarned: lifetimePoints,
        totalRedeemed: totalRedeemed,
        currentBalance: customerData.loyaltyPoints || 0,
        currentTier: currentTier,
        lifetimePoints: lifetimePoints,
        pointsToNextTier: Math.max(0, pointsToNextTier),
        nextTier: nextTier
      },
      pagination: {
        page: parseInt(page),
        limit: parseInt(limit),
        total: history.length,
        hasMore: startIndex + parseInt(limit) < history.length
      }
    });

  } catch (error) {
    console.error('Get loyalty history error:', error);
    res.status(500).json({ error: 'Failed to fetch loyalty history' });
  }
});

// Get customer order history with full details (public endpoint for Crave app)
app.get('/api/public/customer/:customerId/orders', vercelSecurityMiddleware.publicAPI, async (req, res) => {
  try {
    const { customerId } = req.params;
    const { page = 1, limit = 20, status = 'all' } = req.query;

    // Verify customer exists
    const customerDoc = await db.collection('customers').doc(customerId).get();
    if (!customerDoc.exists) {
      return res.status(404).json({ error: 'Customer not found' });
    }

    const customerData = customerDoc.data();
    const restaurantId = customerData.restaurantId;

    // Fetch orders for this customer from the orders collection
    let ordersQuery = db.collection(collections.orders)
      .where('customerId', '==', customerId)
      .orderBy('createdAt', 'desc');

    const ordersSnapshot = await ordersQuery.get();

    let orders = [];
    ordersSnapshot.forEach(doc => {
      const orderData = doc.data();

      // Filter by status if specified
      if (status !== 'all' && orderData.status !== status) {
        return;
      }

      orders.push({
        id: doc.id,
        orderNumber: orderData.orderNumber,
        dailyOrderId: orderData.dailyOrderId ?? null,
        status: orderData.status || 'pending',
        orderType: orderData.orderType,
        orderTypeLabel: orderData.orderTypeLabel,
        items: (orderData.items || []).map(item => ({
          name: item.name,
          quantity: item.quantity,
          price: item.price,
          total: item.quantity * item.price
        })),
        subtotal: orderData.subtotal || 0,
        discountAmount: orderData.discountAmount || 0,
        loyaltyDiscount: orderData.loyaltyDiscount || 0,
        totalAmount: orderData.totalAmount || 0,
        appliedOffer: orderData.appliedOffer ? {
          name: orderData.appliedOffer.name,
          discountApplied: orderData.appliedOffer.discountApplied
        } : null,
        appliedOffers: (orderData.appliedOffers || []).map(o => ({
          name: o.name,
          discountApplied: o.discountApplied
        })),
        loyaltyPointsEarned: orderData.loyaltyPointsEarned || 0,
        loyaltyPointsRedeemed: orderData.loyaltyPointsRedeemed || 0,
        tableNumber: orderData.tableNumber,
        createdAt: orderData.createdAt?.toDate ? orderData.createdAt.toDate().toISOString() : orderData.createdAt,
        completedAt: orderData.completedAt?.toDate ? orderData.completedAt.toDate().toISOString() : orderData.completedAt
      });
    });

    // Pagination
    const startIndex = (parseInt(page) - 1) * parseInt(limit);
    const paginatedOrders = orders.slice(startIndex, startIndex + parseInt(limit));

    res.json({
      orders: paginatedOrders,
      pagination: {
        page: parseInt(page),
        limit: parseInt(limit),
        total: orders.length,
        hasMore: startIndex + parseInt(limit) < orders.length
      },
      summary: {
        totalOrders: orders.length,
        pendingOrders: orders.filter(o => o.status === 'pending').length,
        completedOrders: orders.filter(o => o.status === 'completed').length
      }
    });

  } catch (error) {
    console.error('Get customer orders error:', error);
    res.status(500).json({ error: 'Failed to fetch order history' });
  }
});

// Get customer app settings (public endpoint for Crave app)
app.get('/api/public/customer-app-settings/:restaurantId', vercelSecurityMiddleware.publicAPI, async (req, res) => {
  try {
    const { restaurantId } = req.params;

    // Use KV-cached restaurant data
    const { data: restaurantData } = await getCachedRestaurant(db, collections.restaurants, restaurantId);
    if (!restaurantData) {
      return res.status(404).json({ error: 'Restaurant not found' });
    }
    const customerAppSettings = restaurantData.customerAppSettings || {};
    const taxSettings = restaurantData.taxSettings || {};

    // Build tax breakdown for display (only if enabled)
    let taxInfo = { enabled: false, taxes: [] };
    if (taxSettings.enabled) {
      taxInfo.enabled = true;
      if (taxSettings.taxes && Array.isArray(taxSettings.taxes) && taxSettings.taxes.length > 0) {
        taxInfo.taxes = taxSettings.taxes
          .filter(tax => tax.enabled)
          .map(tax => ({
            name: tax.name || 'Tax',
            rate: tax.rate || 0
          }));
      } else if (taxSettings.defaultTaxRate) {
        taxInfo.taxes = [{ name: 'Tax', rate: taxSettings.defaultTaxRate }];
      }
    }

    // Only return settings that are relevant to customers
    // CDN cache 60s — settings rarely change; invalidated by PUT via KV cache bust
    res.set('Cache-Control', 'public, s-maxage=60, stale-while-revalidate=30');
    res.json({
      settings: {
        enabled: customerAppSettings.enabled ?? false,
        allowDineIn: customerAppSettings.allowDineIn ?? true,
        allowTakeaway: customerAppSettings.allowTakeaway ?? true,
        allowDelivery: customerAppSettings.allowDelivery ?? false,
        requireTableSelection: customerAppSettings.requireTableSelection ?? true,
        minimumOrder: customerAppSettings.minimumOrder || 0,
        loyaltySettings: customerAppSettings.loyaltySettings?.enabled ? {
          enabled: true,
          earnPerAmount: customerAppSettings.loyaltySettings.earnPerAmount || 100,
          pointsEarned: customerAppSettings.loyaltySettings.pointsEarned || 4,
          redemptionRate: customerAppSettings.loyaltySettings.redemptionRate || 1,
          maxRedemptionPercent: customerAppSettings.loyaltySettings.maxRedemptionPercent || 20,
          earnPointsOnRedemption: customerAppSettings.loyaltySettings.earnPointsOnRedemption ?? false,
          earnOnFullAmount: customerAppSettings.loyaltySettings.earnOnFullAmount ?? false
        } : {
          enabled: false
        },
        taxSettings: taxInfo, // Include tax settings for cart display
        branding: {
          primaryColor: customerAppSettings.branding?.primaryColor || '#ef4444',
          textColor: customerAppSettings.branding?.textColor || '#ffffff',
          pageBackgroundColor: customerAppSettings.branding?.pageBackgroundColor || '#f8fafc',
          offerGradientStart: customerAppSettings.branding?.offerGradientStart || '#fef3c7',
          offerGradientEnd: customerAppSettings.branding?.offerGradientEnd || '#fde68a',
          logoUrl: customerAppSettings.branding?.logoUrl || restaurantData.logo || '',
          tagline: customerAppSettings.branding?.tagline || '',
          headerStyle: customerAppSettings.branding?.headerStyle || 'modern'
        },
        offerSettings: {
          autoApplyBestOffer: customerAppSettings.offerSettings?.autoApplyBestOffer ?? false,
          allowMultipleOffers: customerAppSettings.offerSettings?.allowMultipleOffers ?? false,
          maxOffersAllowed: customerAppSettings.offerSettings?.maxOffersAllowed ?? 1
        },
        pageSettings: {
          loginMode: customerAppSettings.pageSettings?.loginMode || 'optional',
          showOffersOnMenu: customerAppSettings.pageSettings?.showOffersOnMenu !== false,
          publicMenuOnly: customerAppSettings.pageSettings?.publicMenuOnly === true,
          collectName: customerAppSettings.pageSettings?.collectName !== false,
          collectEmail: customerAppSettings.pageSettings?.collectEmail === true
        },
        paymentSettings: customerAppSettings.paymentSettings ? {
          upiEnabled: customerAppSettings.paymentSettings.upiEnabled ?? false,
          upiId: customerAppSettings.paymentSettings.upiId || '',
          upiDisplayName: customerAppSettings.paymentSettings.upiDisplayName || '',
          upiQrCodeUrl: customerAppSettings.paymentSettings.upiQrCodeUrl || '',
          razorpayEnabled: customerAppSettings.paymentSettings.razorpayEnabled ?? false,
          razorpayConnected: customerAppSettings.paymentSettings.razorpayConnected ?? false,
        } : { upiEnabled: false, razorpayEnabled: false, razorpayConnected: false },
        billingSettings: {
          tipsEnabled: customerAppSettings.billingSettings?.tipsEnabled ?? false,
          tipPresets: customerAppSettings.billingSettings?.tipPresets || [5, 10, 15],
          serviceChargeEnabled: customerAppSettings.billingSettings?.serviceChargeEnabled ?? false,
          serviceChargeRate: customerAppSettings.billingSettings?.serviceChargeRate || 0,
          serviceChargeLabel: customerAppSettings.billingSettings?.serviceChargeLabel || 'Service Charge',
        }
      }
    });
  } catch (error) {
    console.error('Get public customer app settings error:', error);
    res.status(500).json({ error: 'Failed to fetch settings' });
  }
});

// Get active offers for POS (authenticated, returns full fields including scope, schedule, bogoConfig)
app.get('/api/offers/:restaurantId/active', authenticateToken, async (req, res) => {
  try {
    const { restaurantId } = req.params;
    const { isFirstOrder } = req.query;
    const now = new Date();

    const customerIsFirstOrder = isFirstOrder === 'true' ? true : isFirstOrder === 'false' ? false : undefined;

    const offersSnapshot = await db.collection('offers')
      .where('restaurantId', '==', restaurantId)
      .where('isActive', '==', true)
      .get();

    // Also fetch offers targeting 'all' restaurants from same owner
    const restaurant = await db.collection(collections.restaurants).doc(restaurantId).get();
    const ownerId = restaurant.exists ? restaurant.data().ownerId : null;
    let crossRestaurantOffers = [];
    if (ownerId) {
      const ownerRestaurants = await db.collection(collections.restaurants)
        .where('ownerId', '==', ownerId)
        .get();
      const ownerRestaurantIds = ownerRestaurants.docs.map(d => d.id).filter(id => id !== restaurantId);
      for (const rId of ownerRestaurantIds) {
        const otherOffers = await db.collection('offers')
          .where('restaurantId', '==', rId)
          .where('isActive', '==', true)
          .get();
        otherOffers.forEach(doc => {
          const offer = doc.data();
          if (offer.targetRestaurants === 'all' || (Array.isArray(offer.targetRestaurants) && offer.targetRestaurants.includes(restaurantId))) {
            crossRestaurantOffers.push({ id: doc.id, ...offer });
          }
        });
      }
    }

    const offers = [];
    const processOffer = (doc, offerData) => {
      const offer = offerData || doc.data();
      const docId = offerData ? offer.id : doc.id;

      let validFrom = null;
      let validUntil = null;
      if (offer.validFrom) {
        validFrom = offer.validFrom.toDate ? offer.validFrom.toDate() : new Date(offer.validFrom);
      }
      if (offer.validUntil) {
        validUntil = offer.validUntil.toDate ? offer.validUntil.toDate() : new Date(offer.validUntil);
        // If validUntil is a date-only string (e.g. "2026-04-06"), it parses to midnight UTC.
        // Treat it as end-of-day by adding 23:59:59 so the offer is valid for the entire last day.
        if (typeof offer.validUntil === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(offer.validUntil)) {
          validUntil = new Date(offer.validUntil + 'T23:59:59.999Z');
        }
      }

      const isValidDate = (!validFrom || now >= validFrom) && (!validUntil || now <= validUntil);
      const isUnderUsageLimit = !offer.usageLimit || (offer.usageCount || 0) < offer.usageLimit;
      const isEligibleForFirstOrderOffer = !offer.isFirstOrderOnly || customerIsFirstOrder !== false;

      if (isValidDate && isUnderUsageLimit && isEligibleForFirstOrderOffer) {
        offers.push({
          id: docId,
          name: offer.name,
          description: offer.description,
          discountType: offer.discountType,
          discountValue: offer.discountValue,
          minOrderValue: offer.minOrderValue || 0,
          maxDiscount: offer.maxDiscount,
          validFrom: validFrom ? validFrom.toISOString() : null,
          validUntil: validUntil ? validUntil.toISOString() : null,
          isActive: offer.isActive ?? true,
          usageLimit: offer.usageLimit || null,
          usageCount: offer.usageCount || 0,
          isFirstOrderOnly: offer.isFirstOrderOnly || false,
          autoApply: offer.autoApply || false,
          scope: offer.scope || 'order',
          targetCategories: offer.targetCategories || [],
          targetItems: offer.targetItems || [],
          schedule: offer.schedule || null,
          promotionType: offer.promotionType || 'discount',
          bogoConfig: offer.bogoConfig || null,
          eventLabel: offer.eventLabel || null,
          targetRestaurants: offer.targetRestaurants || 'all',
          audience: offer.audience || null,
          tiers: offer.tiers || null,
        });
      }
    };

    offersSnapshot.forEach(doc => processOffer(doc, null));
    crossRestaurantOffers.forEach(offer => processOffer(null, offer));

    // Deduplicate by id
    const uniqueOffers = [...new Map(offers.map(o => [o.id, o])).values()];

    res.json({ offers: uniqueOffers });
  } catch (error) {
    console.error('Get active offers for POS error:', error);
    res.status(500).json({ error: 'Failed to fetch active offers' });
  }
});

// Get active offers for a restaurant (public endpoint for Crave app)
// Query params:
// - isFirstOrder=true/false - Filter first-order-only offers based on customer status
// Public customer-groups lookup — returns only the groups a phone/customerId belongs to.
// Used by the public /placeorder page to unlock targeted offers without exposing PII.
app.get('/api/public/customer-groups/lookup/:restaurantId', vercelSecurityMiddleware.publicAPI, async (req, res) => {
  try {
    const { restaurantId } = req.params;
    const rawPhone = req.query.phone;
    const customerId = req.query.customerId || null;
    const normalizePhone = (raw) => {
      if (!raw) return '';
      const digits = String(raw).replace(/\D/g, '');
      return digits.length > 10 ? digits.slice(-10) : digits;
    };
    const phone = normalizePhone(rawPhone);
    if (!phone && !customerId) {
      return res.status(400).json({ success: false, error: 'phone or customerId required' });
    }
    const snap = await db.collection('customerGroups')
      .where('restaurantId', '==', restaurantId)
      .get();
    const groups = [];
    snap.forEach(doc => {
      const d = doc.data();
      const inIds = customerId && Array.isArray(d.customerIds) && d.customerIds.includes(customerId);
      const inPhones = phone && Array.isArray(d.customerPhones) && d.customerPhones.includes(phone);
      if (inIds || inPhones) groups.push({ id: doc.id, name: d.name, color: d.color });
    });
    // Short edge cache; groups rarely change
    res.set('Cache-Control', 'public, s-maxage=60, stale-while-revalidate=30');
    res.json({ success: true, groups });
  } catch (err) {
    console.error('[public customerGroups lookup] error', err);
    res.status(500).json({ success: false, error: 'Lookup failed' });
  }
});

app.get('/api/public/offers/:restaurantId', vercelSecurityMiddleware.publicAPI, async (req, res) => {
  try {
    const { restaurantId } = req.params;
    const { isFirstOrder } = req.query;
    const now = new Date();

    // Parse isFirstOrder query param (default to undefined if not provided)
    const customerIsFirstOrder = isFirstOrder === 'true' ? true : isFirstOrder === 'false' ? false : undefined;

    // Try Redis cache first (cache all active offers, filter in-memory)
    const offersCacheKey = `offers:${restaurantId}`;
    let allOffers = await kvGet(offersCacheKey);

    if (!allOffers) {
      // Cache miss — read from Firestore
      const offersSnapshot = await db.collection('offers')
        .where('restaurantId', '==', restaurantId)
        .where('isActive', '==', true)
        .get();

      allOffers = [];
      offersSnapshot.forEach(doc => {
        const offer = doc.data();

        // Handle Firestore Timestamps - convert to JS Date for caching
        let validFrom = null;
        let validUntil = null;

        if (offer.validFrom) {
          validFrom = offer.validFrom.toDate ? offer.validFrom.toDate().toISOString() : new Date(offer.validFrom).toISOString();
        }
        if (offer.validUntil) {
          // If validUntil is a date-only string (e.g. "2026-04-06"), treat as end-of-day
          if (typeof offer.validUntil === 'string' && /^\d{4}-\d{2}-\d{2}$/.test(offer.validUntil)) {
            validUntil = new Date(offer.validUntil + 'T23:59:59.999Z').toISOString();
          } else {
            validUntil = offer.validUntil.toDate ? offer.validUntil.toDate().toISOString() : new Date(offer.validUntil).toISOString();
          }
        }

        allOffers.push({
          id: doc.id,
          name: offer.name,
          description: offer.description,
          discountType: offer.discountType,
          discountValue: offer.discountValue,
          minOrderValue: offer.minOrderValue || 0,
          maxDiscount: offer.maxDiscount,
          validFrom,
          validUntil,
          isActive: offer.isActive ?? true,
          usageLimit: offer.usageLimit || null,
          usageCount: offer.usageCount || 0,
          isFirstOrderOnly: offer.isFirstOrderOnly || false,
          autoApply: offer.autoApply || false,
          scope: offer.scope || 'order',
          targetCategories: offer.targetCategories || [],
          targetItems: offer.targetItems || [],
          schedule: offer.schedule || null,
          promotionType: offer.promotionType || 'discount',
          bogoConfig: offer.bogoConfig || null,
          eventLabel: offer.eventLabel || null,
          // Phase 4: extended offer engine fields
          audience: offer.audience || null,
          tiers: offer.tiers || null,
          crossItemBogo: offer.crossItemBogo || null,
          perCustomerUsageLimit: offer.perCustomerUsageLimit || null
        });
      });

      // Cache for 3 min (fire-and-forget)
      kvSet(offersCacheKey, allOffers, 180).catch(() => {});
    }

    // Filter cached offers by date, usage, and first-order eligibility
    const offers = allOffers.filter(offer => {
      const validFrom = offer.validFrom ? new Date(offer.validFrom) : null;
      const validUntil = offer.validUntil ? new Date(offer.validUntil) : null;
      const isValidDate = (!validFrom || now >= validFrom) && (!validUntil || now <= validUntil);
      const isUnderUsageLimit = !offer.usageLimit || (offer.usageCount || 0) < offer.usageLimit;
      const isEligibleForFirstOrderOffer = !offer.isFirstOrderOnly || customerIsFirstOrder !== false;
      return isValidDate && isUnderUsageLimit && isEligibleForFirstOrderOffer;
    });

    // Cache at Vercel Edge for 3 min
    res.set('Cache-Control', 'public, s-maxage=180, stale-while-revalidate=60');
    res.json({ offers });
  } catch (error) {
    console.error('Get public offers error:', error);
    res.status(500).json({ error: 'Failed to fetch offers' });
  }
});

// Create a new offer
app.post('/api/offers/:restaurantId', authenticateToken, async (req, res) => {
  try {
    // Granular permission check: offers.add
    if (!(await checkFeaturePermission(req, 'offers', 'add'))) {
      return res.status(403).json({ error: 'Access denied. Offers add permission required.' });
    }
    const { restaurantId } = req.params;
    const { userId } = req.user;
    const {
      name,
      description,
      discountType = 'percentage',
      discountValue,
      minOrderValue = 0,
      maxDiscount = null,
      validFrom,
      validUntil,
      isActive = true,
      usageLimit = null,
      isFirstOrderOnly = false,
      autoApply = false,
      // Enhanced offer fields
      scope = 'order',
      targetCategories = [],
      targetItems = [],
      schedule = null,
      promotionType = 'discount',
      bogoConfig = null,
      eventLabel = null,
      targetRestaurants = 'all',
      // Phase 2 additions (all optional, back-compat)
      audience = null,
      tiers = null,
      crossItemBogo = null,
      usageLimitPerCustomer = null,
      priority = 0
    } = req.body;

    // Verify user has access to this restaurant
    const restaurant = await db.collection(collections.restaurants).doc(restaurantId).get();
    if (!restaurant.exists || restaurant.data().ownerId !== userId) {
      return res.status(403).json({ error: 'Access denied' });
    }

    if (!name) {
      return res.status(400).json({ error: 'Offer name is required' });
    }

    if (promotionType !== 'bogo') {
      if (!discountValue || discountValue <= 0) {
        return res.status(400).json({ error: 'Valid discount value is required' });
      }

      if (discountType === 'percentage' && discountValue > 100) {
        return res.status(400).json({ error: 'Percentage discount cannot exceed 100%' });
      }
    }

    const offerData = {
      restaurantId,
      name,
      description: description || '',
      discountType,
      discountValue: Number(discountValue) || 0,
      minOrderValue: Number(minOrderValue) || 0,
      maxDiscount: maxDiscount ? Number(maxDiscount) : null,
      validFrom: validFrom || null,
      validUntil: validUntil || null,
      isActive,
      usageLimit: usageLimit ? Number(usageLimit) : null,
      usageCount: 0,
      isFirstOrderOnly,
      autoApply,
      // Enhanced fields
      scope,
      targetCategories: Array.isArray(targetCategories) ? targetCategories : [],
      targetItems: Array.isArray(targetItems) ? targetItems : [],
      schedule: schedule || null,
      promotionType,
      bogoConfig: bogoConfig ? {
        buyQty: Number(bogoConfig.buyQty) || 2,
        getQty: Number(bogoConfig.getQty) || 1,
        getDiscount: Number(bogoConfig.getDiscount) || 100
      } : null,
      eventLabel: eventLabel || null,
      targetRestaurants: targetRestaurants || 'all',
      // Phase 2 additions
      audience: audience && typeof audience === 'object' ? audience : null,
      tiers: Array.isArray(tiers) ? tiers : null,
      crossItemBogo: crossItemBogo && typeof crossItemBogo === 'object' ? crossItemBogo : null,
      usageLimitPerCustomer: usageLimitPerCustomer ? Number(usageLimitPerCustomer) : null,
      priority: Number(priority) || 0,
      createdAt: new Date(),
      updatedAt: new Date()
    };

    const offerRef = await db.collection('offers').add(offerData);

    // Invalidate offers cache so public endpoint serves fresh data
    kvDel(`offers:${restaurantId}`).catch(() => {});

    // Notify all connected clients (POS, dashboard) about offer change
    pusherService.triggerOrderEvent(restaurantId, 'offer-updated', { offerId: offerRef.id, action: 'created' });

    res.status(201).json({
      message: 'Offer created successfully',
      offer: {
        id: offerRef.id,
        ...offerData
      }
    });
  } catch (error) {
    console.error('Create offer error:', error);
    res.status(500).json({ error: 'Failed to create offer' });
  }
});

// Update an offer
app.put('/api/offers/:restaurantId/:offerId', authenticateToken, async (req, res) => {
  try {
    // Granular permission check: offers.update
    if (!(await checkFeaturePermission(req, 'offers', 'update'))) {
      return res.status(403).json({ error: 'Access denied. Offers update permission required.' });
    }
    const { restaurantId, offerId } = req.params;
    const { userId } = req.user;
    const updateData = req.body;

    // Verify user has access to this restaurant
    const restaurant = await db.collection(collections.restaurants).doc(restaurantId).get();
    if (!restaurant.exists || restaurant.data().ownerId !== userId) {
      return res.status(403).json({ error: 'Access denied' });
    }

    // Get offer and verify it belongs to this restaurant
    const offerDoc = await db.collection('offers').doc(offerId).get();
    if (!offerDoc.exists) {
      return res.status(404).json({ error: 'Offer not found' });
    }

    if (offerDoc.data().restaurantId !== restaurantId) {
      return res.status(403).json({ error: 'Offer does not belong to this restaurant' });
    }

    // Validate discount value
    if (updateData.discountValue !== undefined) {
      if (updateData.discountValue <= 0) {
        return res.status(400).json({ error: 'Valid discount value is required' });
      }
      if (updateData.discountType === 'percentage' && updateData.discountValue > 100) {
        return res.status(400).json({ error: 'Percentage discount cannot exceed 100%' });
      }
    }

    const updatedData = {
      ...updateData,
      discountValue: updateData.discountValue ? Number(updateData.discountValue) : offerDoc.data().discountValue,
      minOrderValue: updateData.minOrderValue !== undefined ? Number(updateData.minOrderValue) : offerDoc.data().minOrderValue,
      maxDiscount: updateData.maxDiscount !== undefined ? (updateData.maxDiscount ? Number(updateData.maxDiscount) : null) : offerDoc.data().maxDiscount,
      usageLimit: updateData.usageLimit !== undefined ? (updateData.usageLimit ? Number(updateData.usageLimit) : null) : offerDoc.data().usageLimit,
      updatedAt: new Date()
    };

    // Remove fields that shouldn't be updated
    delete updatedData.restaurantId;
    delete updatedData.createdAt;
    delete updatedData.id;

    await offerDoc.ref.update(updatedData);

    // Invalidate offers cache so public endpoint serves fresh data
    kvDel(`offers:${restaurantId}`).catch(() => {});

    // Notify all connected clients (POS, dashboard) about offer change
    pusherService.triggerOrderEvent(restaurantId, 'offer-updated', { offerId, action: 'updated' });

    res.json({
      message: 'Offer updated successfully',
      offer: {
        id: offerId,
        ...offerDoc.data(),
        ...updatedData
      }
    });
  } catch (error) {
    console.error('Update offer error:', error);
    res.status(500).json({ error: 'Failed to update offer' });
  }
});

// Delete an offer
app.delete('/api/offers/:restaurantId/:offerId', authenticateToken, async (req, res) => {
  try {
    // Granular permission check: offers.delete
    if (!(await checkFeaturePermission(req, 'offers', 'delete'))) {
      return res.status(403).json({ error: 'Access denied. Offers delete permission required.' });
    }
    const { restaurantId, offerId } = req.params;
    const { userId } = req.user;

    // Verify user has access to this restaurant
    const restaurant = await db.collection(collections.restaurants).doc(restaurantId).get();
    if (!restaurant.exists || restaurant.data().ownerId !== userId) {
      return res.status(403).json({ error: 'Access denied' });
    }

    // Get offer and verify it belongs to this restaurant
    const offerDoc = await db.collection('offers').doc(offerId).get();
    if (!offerDoc.exists) {
      return res.status(404).json({ error: 'Offer not found' });
    }

    if (offerDoc.data().restaurantId !== restaurantId) {
      return res.status(403).json({ error: 'Offer does not belong to this restaurant' });
    }

    await offerDoc.ref.delete();

    // Invalidate offers cache so public endpoint serves fresh data
    kvDel(`offers:${restaurantId}`).catch(() => {});

    // Notify all connected clients (POS, dashboard) about offer change
    pusherService.triggerOrderEvent(restaurantId, 'offer-updated', { offerId, action: 'deleted' });

    res.json({
      message: 'Offer deleted successfully'
    });
  } catch (error) {
    console.error('Delete offer error:', error);
    res.status(500).json({ error: 'Failed to delete offer' });
  }
});

